import { Component, computed, inject, input, signal } from '@angular/core';

import { MessageModule } from 'primeng/message';
import { ProgressSpinnerModule } from 'primeng/progressspinner';

import {
  ClientListItem,
  ClientResponse,
  ClientCreateRequest,
  AccountsService,
} from '../../../../../api';
import { isNullOrUndefined } from '../../../../../shared/utils';
import { EntityDetailsStateService } from '../../../services/entity/entity-details.state.service';
import { EntityOperationRegistryService } from '../../../services/entity/entity-operation-registry.service';
import { DetailsAccordionContainerComponent } from '../../details-accordion-container/details-accordion-container.component';
import { ClientSectionConfigFactory } from '../../../factories';
import { AuthDataService } from '../../../../../core/services/auth-data.service';
import { AppFeatures } from '../../../../../core/models';

@Component({
  selector: 'app-vendor-client-details-container',
  imports: [
    DetailsAccordionContainerComponent,
    ProgressSpinnerModule,
    MessageModule,
  ],
  templateUrl: './vendor-client-details-container.component.html',
  styleUrl: './vendor-client-details-container.component.scss',
})
export class VendorClientDetailsContainerComponent {
  readonly entity = input<ClientListItem | null>(null);

  private readonly clientSectionFactory = inject(ClientSectionConfigFactory);
  readonly entityDetailsState = inject(EntityDetailsStateService);
  private readonly accountsService = inject(AccountsService);
  private readonly operationRegistry = inject(EntityOperationRegistryService);
  private readonly authDataService = inject(AuthDataService);

  readonly isLoading = computed(() => this.entityDetailsState.isLoading());
  readonly isSoftRefreshing = computed(() =>
    this.entityDetailsState.isSoftRefreshing(),
  );
  readonly isInitialLoading = computed(
    () => this.isLoading() && !this.isSoftRefreshing() && !this.fullClient(),
  );
  readonly fullClient = computed(() => {
    const entityDetails = this.entityDetailsState.selectedItem();

    if (isNullOrUndefined(entityDetails)) {
      return null;
    }
    return entityDetails as ClientResponse;
  });
  readonly sections = computed(() => {
    const client = this.fullClient();
    if (isNullOrUndefined(client)) return [];

    if (this.authDataService.getUserProfile()?.owner?.type !== 'client') {
      let appFeatures = Object.keys(AppFeatures);
      const useFlags = this.authDataService.flags;
      if (isNullOrUndefined(useFlags.assetPerformanceEnabled())) {
        // Asset performance is not available, hide the feature flag section.
        appFeatures = appFeatures.filter(
          (feature) => feature !== 'page-assetperformance',
        );
      }
      if (isNullOrUndefined(useFlags.deviceHealthEnabled())) {
        appFeatures = appFeatures.filter(
          (feature) => feature !== 'page-devicehealth',
        );
      }

      return this.clientSectionFactory.createAllClientSections(
        client,
        appFeatures,
      );
    }

    return [];
  });
  readonly error = signal<string | null>(null);

  constructor() {
    this.operationRegistry.registerEntityOperations('client', {
      update: (id, data) => this.accountsService.updateClient(id, data),
      create: (data: ClientCreateRequest) =>
        this.accountsService.createClient(data),
      get: (id) => this.accountsService.getClient(id),
    });
  }

  onEntityChange(entity: unknown): void {
    this.entityDetailsState.updateEntity(entity as ClientResponse);
    this.error.set(null);
  }
}
