import {
  ChangeDetectorRef,
  Component,
  computed,
  effect,
  inject,
  signal,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { Validators } from '@angular/forms';
import { Observable } from 'rxjs';

// PrimeNG imports
import { ButtonModule } from 'primeng/button';

// Core imports
import {
  AccountsService,
  AssetTagCreateRequest,
  CustomFieldDefinition,
  EntitiesService,
  IdName,
} from '../../../../../api';
import {
  createDateField,
  createDropdownField,
  createNumberField,
  createTextAreaField,
  createTextField,
  createToggleSwitchField,
} from '../../../../../shared/models';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../base';
import { AdminStateService } from '../../../services/admin-state.service';

// Lazy loaded components
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import { RequestCacheService } from '../../../../../shared/services/request-cache.service';

interface EntityWithFields {
  id: string;
  assetType?: IdName;
  fields?: Record<string, string | boolean | number | object>;
}

@Component({
  selector: 'app-info-section',
  imports: [CommonModule, ButtonModule, GridComponent, DynamicFormComponent],
  templateUrl: './info-section.component.html',
  styleUrl: './info-section.component.scss',
})
export class InfoSectionComponent<
  T extends EntityWithFields,
> extends EntitySectionBaseComponent<T> {
  private readonly entitiesService = inject(EntitiesService);
  private readonly adminStateService = inject(AdminStateService);
  private readonly cacheService = inject(RequestCacheService);
  private readonly accountsService = inject(AccountsService);
  private readonly cdr = inject(ChangeDetectorRef);

  readonly entityCustomFields = signal<CustomFieldDefinition[]>([]);

  readonly entityDetails = computed(() => {
    const entityDetails = this.entity();
    const selectedClient = this.adminStateService.selectedClient();

    if (isNullOrUndefined(entityDetails) || isNullOrUndefined(selectedClient)) {
      return [];
    }

    // Return the details without side effects
    return this.entityCustomFields().map((field) => ({
      key: field['title'],
      value: entityDetails['fields']?.[field['id']] ?? 'None',
    }));
  });

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    effect(() => {
      const entityDetails = this.entity();
      const selectedClientId = this.adminStateService.selectedClient()?.id;
      if (isNullOrUndefined(selectedClientId)) {
        this.entityCustomFields.set([]);
        return;
      }
      this.cacheService
        .getOrFetch(`custom-fields-${selectedClientId}`, () =>
          this.accountsService.getClient(selectedClientId),
        )
        .subscribe((client) => {
          if (isDefined(client)) {
            // Update the custom fields signal
            this.entityCustomFields.set([
              ...(client.customFields?.[this.entityType()] ?? []),
              ...((entityDetails?.assetType &&
                client.customFields?.[entityDetails.assetType.id]) ??
                []),
            ]);
            this.updateFormFields();
            this.cdr.detectChanges();
          }
        });
    });
  }

  protected override updateFormFields(): void {
    const entity = this.entity();
    this.formFields = this.entityCustomFields().map((field) => {
      const fieldValue = entity?.fields?.[field['id']];
      let formattedValue: string | boolean | number | object = '';
      if (isDefined(fieldValue)) {
        formattedValue =
          typeof fieldValue === 'object'
            ? JSON.stringify(fieldValue)
            : fieldValue;
      }

      switch (field['type']) {
        case 'number':
          return createNumberField(
            String(field['id']),
            String(field['title']),
            formattedValue as number,
            {
              name: String(field['id']),
              validations: field['required']
                ? [
                    {
                      name: 'required',
                      validator: Validators.required,
                      message: `${field['title']} is required`,
                    },
                  ]
                : [],
            },
          );
        case 'combo':
          return createDropdownField(
            String(field['id']),
            String(field['title']),
            field.values?.map((value) => ({
              label: String(value.key),
              value: String(value.value),
            })) ?? [],
            formattedValue as string,
            {
              name: String(field['id']),
              validations: field['required']
                ? [
                    {
                      name: 'required',
                      validator: Validators.required,
                      message: `${field['title']} is required`,
                    },
                  ]
                : [],
            },
          );
        case 'memo':
          return createTextAreaField(
            String(field?.id),
            String(field['title']),
            formattedValue as string,
            {
              name: String(field?.id),
              validations: field['required']
                ? [
                    {
                      name: 'required',
                      validator: Validators.required,
                      message: `${field['title']} is required`,
                    },
                  ]
                : [],
              hint: field['description'],
            },
          );
        case 'checkbox':
          return createToggleSwitchField(
            field.id,
            field.title,
            formattedValue as boolean,
            {
              name: field.id,
              validations: field['required']
                ? [
                    {
                      name: 'required',
                      validator: Validators.required,
                      message: `${field['title']} is required`,
                    },
                  ]
                : [],
              hint: field['description'],
            },
          );

        case 'date':
          return createDateField(
            field.id,
            field.title,
            entity?.fields?.[field.id] as unknown as Date,
            {
              name: field.id,
              validations: field['required']
                ? [
                    {
                      name: 'required',
                      validator: Validators.required,
                      message: `${field['title']} is required`,
                    },
                  ]
                : [],
              hint: field['hint'],
              props: {
                showTime: false,
                timeOnly: false,
                dateFormat: 'mm/dd/yy',
                hourFormat: '24',
                showIcon: true,
                appendTo: 'body',
              },
            },
          );

        case 'datetime':
          return createDateField(
            field.id,
            field.title,
            entity?.fields?.[field.id] as unknown as Date,
            {
              name: field.id,
              validations: field['required']
                ? [
                    {
                      name: 'required',
                      validator: Validators.required,
                      message: `${field['title']} is required`,
                    },
                  ]
                : [],
              hint: field['hint'],
              props: {
                showTime: true,
                timeOnly: false,
                dateFormat: 'mm/dd/yy',
                hourFormat: '24',
                showIcon: true,
                appendTo: 'body',
              },
            },
          );
        default:
          return createTextField(
            String(field['id']),
            String(field['title']),
            formattedValue as string,
            {
              name: String(field['id']),
              validations: field['required']
                ? [
                    {
                      name: 'required',
                      validator: Validators.required,
                      message: `${field['title']} is required`,
                    },
                  ]
                : [],
            },
          );
      }
    });
  }

  override getUpdateMethod(): (
    id: string,
    payload: object | Record<string, string | number | boolean>,
  ) => Observable<unknown> {
    switch (this.entityType()) {
      case 'asset':
        return (id, payload) =>
          this.entitiesService.updateAsset(id, {
            fields: payload as Record<string, object>,
          });
      case 'simcard':
        return (id, payload) =>
          this.entitiesService.updateSimCard(id, {
            fields: payload as Record<string, object>,
          });
      case 'device':
        return (id, payload) =>
          this.entitiesService.updateDevice(id, {
            fields: payload as Record<string, object>,
          });
      case 'assettag':
        return (id, payload) =>
          this.entitiesService.updateAssetTag(
            id,
            payload as AssetTagCreateRequest,
          );
      default:
        throw new Error(`Update for '${this.entityType}' not yet supported`);
    }
  }

  protected override onFormValueChange(
    formData: Record<string, string | number | object>,
  ): void {
    const transformedData = { fields: formData };

    // Emit the transformed values
    this.formValueChange.emit(transformedData);
  }
}
