import {
  Component,
  computed,
  effect,
  inject,
  OnInit,
  signal,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import {
  combineLatest,
  catchError,
  of,
  Subject,
  distinctUntilChanged,
  switchMap,
  debounceTime,
} from 'rxjs';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule } from '@angular/forms';

import { ButtonModule } from 'primeng/button';
import { ChipModule } from 'primeng/chip';
import { InputTextModule } from 'primeng/inputtext';

import {
  AssetRatingProfileListItem,
  AssetRatingProfileListResponse,
  AssetResponse,
  EntitiesService,
} from '../../../../../api';
import {
  createMultiselectField,
  createDropdownField,
  createAutocompleteField,
} from '../../../../../shared/models';
import {
  isDefined,
  isNullOrUndefined,
  isString,
} from '../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../base';
import {
  DEFAULT_LIST_SIZE,
  DEFAULT_SYSTEM_ID,
} from '../../../../../core/models';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';

import { UtilityService } from '../../../../../core/services/utility.service';
import { isEmpty } from 'lodash';

@Component({
  selector: 'app-asset-profiles-section',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    ButtonModule,
    InputTextModule,
    ChipModule,
    GridComponent,
    DynamicFormComponent,
  ],
  templateUrl: './asset-profiles-section.component.html',
  styleUrl: './asset-profiles-section.component.scss',
})
export class AssetProfilesSectionComponent
  extends EntitySectionBaseComponent<AssetResponse>
  implements OnInit
{
  private readonly entitiesService = inject(EntitiesService);
  private readonly utilityService = inject(UtilityService);
  protected readonly selectOptionsLoaded = signal<boolean>(false);
  selectOptions: Record<string, { label: string; value: string }[]> = {};

  readonly assetDetails = computed(() => {
    const assetDetails = this.entity();
    if (!isDefined(assetDetails)) return [];

    return [
      {
        key: 'Asset Rating',
        value: assetDetails.ratingProfile?.name ?? 'None',
      },
      {
        key: 'Asset State',
        value: !isEmpty(assetDetails.assetStateProfiles)
          ? assetDetails.assetStateProfiles
              ?.map((state) => state.name)
              .join(', ')
          : 'None',
      },
      {
        key: 'Road Profile',
        value: assetDetails.roadProfile?.name ?? 'None',
      },
      {
        key: 'Geo Lock Profile',
        value: assetDetails.geoLockProfile?.name ?? 'None',
      },
    ];
  });
  private readonly searchAssetRatingSubject = new Subject<string>();
  private readonly assetRatingSuggestions = signal<
    AssetRatingProfileListItem[]
  >([]);

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    // React to entity changes
    effect(() => {
      const assetDetails = this.entity();
      if (assetDetails && this.selectOptionsLoaded()) {
        this.updateFormFields();
      }
    });
  }

  ngOnInit() {
    this.loadSelectOptions();
    this.setupSearchAssetRating();
  }

  private loadSelectOptions() {
    const asset = this.entity();
    if (!isDefined(asset) || !isString(asset.id)) {
      this.selectOptions = {};
      this.selectOptionsLoaded.set(true);
      return;
    }

    combineLatest([
      this.entitiesService.listGeoLockProfiles(
        asset.owner.id,
        true,
        0,
        100,
        'name',
        'state=active',
      ),
      this.entitiesService.listRoadProfiles(
        asset.owner.id,
        true,
        0,
        100,
        'name',
        'state=active',
      ),
      this.entitiesService.listAssetStateProfiles(asset.owner.id),
    ])
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        catchError(() => {
          return of([{ items: [] }, { items: [] }, { items: [] }]);
        }),
      )
      .subscribe(([geoLockProfiles, roadProfiles, assetStateProfiles]) => {
        const noneOption = { label: 'None', value: DEFAULT_SYSTEM_ID };

        this.selectOptions = {
          geoLockProfiles: [
            noneOption,
            ...geoLockProfiles.items
              .map((item) => ({
                label: item.name ?? '',
                value: item.id,
              }))
              .sort((a, b) => a.label.localeCompare(b.label)),
          ],
          roadProfiles: [
            noneOption,
            ...roadProfiles.items
              .map((item) => ({
                label: item.name ?? '',
                value: item.id,
              }))
              .sort((a, b) => a.label.localeCompare(b.label)),
          ],
          assetStateProfiles: assetStateProfiles.items
            .map((item) => ({
              label: item.name ?? '',
              value: item.id,
            }))
            .sort((a, b) => a.label.localeCompare(b.label)),
        };

        this.selectOptionsLoaded.set(true);
      });
  }

  private setupSearchAssetRating() {
    this.searchAssetRatingSubject
      .pipe(
        debounceTime(300),
        distinctUntilChanged(),
        takeUntilDestroyed(this.destroyRef),
        switchMap((searchTerm) => {
          if (isNullOrUndefined(searchTerm)) {
            return of({
              count: 0,
              offset: 0,
              limit: DEFAULT_LIST_SIZE,
              items: [],
            } as AssetRatingProfileListResponse);
          }

          const filters = {
            state: 'active',
            name: `*${searchTerm}*`,
          };
          const rqlFilter = this.utilityService.constructRqlFilter(filters);

          return this.entitiesService.listAssetRatingProfiles(
            this.entity()?.owner.id ?? '',
            0,
            10,
            'name',
            rqlFilter,
          );
        }),
      )
      .subscribe((response: AssetRatingProfileListResponse) => {
        this.assetRatingSuggestions.set(response.items);
      });
  }

  private searchAssetRating(searchTerm: string) {
    if (isNullOrUndefined(searchTerm)) {
      this.assetRatingSuggestions.set([]);
      return;
    }

    this.searchAssetRatingSubject.next(searchTerm);
  }

  protected override updateFormFields(): void {
    const asset = this.entity();
    this.formFields = [
      createAutocompleteField(
        'assetRating',
        'Asset Rating',
        asset?.ratingProfile?.name,
        this.assetRatingSuggestions(),
        this.searchAssetRating.bind(this),
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'assetRating',
          props: {
            appendTo: 'body',
            showClear: true,
            multiple: false,
            field: 'name',
          },
        },
      ),
      createMultiselectField(
        'assetStates',
        'Asset State',
        asset?.assetStateProfiles ?? [],
        this.selectOptions?.['assetStateProfiles'] ?? [],
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'assetStates',
          props: {
            appendTo: 'body',
            multiple: true,
            showClear: true,
          },
        },
      ),
      createDropdownField(
        'roadProfile',
        'Road Profile',
        this.selectOptions?.['roadProfiles'] ?? [],
        asset?.roadProfile?.id,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'roadProfile',
          props: {
            appendTo: 'body',
          },
        },
      ),
      createDropdownField(
        'geoLockProfile',
        'Geo Lock Profile',
        this.selectOptions?.['geoLockProfiles'] ?? [],
        asset?.geoLockProfile?.id,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'geoLockProfile',
          props: {
            appendTo: 'body',
          },
        },
      ),
    ];
  }

  protected override submitChanges(
    formData: Record<string, string | number>,
  ): void {
    const asset = this.entity();
    if (isNullOrUndefined(asset)) return;
    this.entitiesService
      .updateAsset(asset.id, formData)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: () => {
          this.isFormEditable.set(false);
        },
        error: () => {
          this.isFormEditable.set(true);
        },
      });
  }
}
