import {
  Component,
  computed,
  effect,
  inject,
  OnInit,
  signal,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import {
  AssetAnalogParameter,
  AssetResponse,
  AssetTemperatureParameter,
  EntitiesService,
  IoTypeListItem,
} from '../../../../../api';
import {
  MeasurementUnitType,
  createNumberField,
  createDropdownField,
  FormAction,
} from '../../../../../shared/models';
import { MeasurementUnitsService } from '../../../../../shared/services/measurement-units/measurement-units.service';
import {
  isDefined,
  isEmpty,
  isNullOrUndefined,
  isString,
} from '../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../base';
import { CommonModule } from '@angular/common';
import { FormGroup, ReactiveFormsModule } from '@angular/forms';
import { ButtonModule } from 'primeng/button';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import { DynamicFormModalComponent } from '../../../../../shared/components/forms/dynamic-form-modal/dynamic-form-modal.component';
import { CardModule } from 'primeng/card';
import { DEFAULT_LIST_SIZE } from '../../../../../core/models';
import { UtilityService } from '../../../../../core/services/utility.service';
import { ApiSchemaService } from '../../../../../core/services/api-schema.service';
import { combineLatest } from 'rxjs';
import {
  AnalogTriggerListItem,
  TemperatureTriggerListItem,
} from '../../../models';

@Component({
  selector: 'app-asset-analog-triggers-section',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    ButtonModule,
    GridComponent,
    DynamicFormModalComponent,
    CardModule,
  ],
  templateUrl: './asset-analog-triggers-section.component.html',
  styleUrl: './asset-analog-triggers-section.component.scss',
})
export class AssetAnalogTriggersSectionComponent
  extends EntitySectionBaseComponent<AssetResponse>
  implements OnInit
{
  private readonly entitiesService = inject(EntitiesService);
  private readonly measurementUnitsService = inject(MeasurementUnitsService);
  private readonly utilityService = inject(UtilityService);
  private readonly apiSchemaService = inject(ApiSchemaService);

  private currentModalType: 'analog' | 'temperature' | null = null;

  protected readonly selectOptionsLoaded = signal<boolean>(false);
  selectOptions: Record<
    string,
    { label: string; value: string; type: string }[]
  > = {};

  readonly analogTriggers = signal<AnalogTriggerListItem[]>([]);
  readonly temperatureTriggers = signal<TemperatureTriggerListItem[]>([]);

  readonly assetAnalogAndTemperatureTriggersList = computed(() => {
    return [
      {
        key: 'Analogs',
        value:
          this.analogTriggers().length > 0
            ? this.analogTriggers()
                .map((analog) => analog.name)
                .join(', ')
            : 'None',
      },
      {
        key: 'Temperature',
        value:
          this.temperatureTriggers().length > 0
            ? this.temperatureTriggers()
                .map((temp) => temp.name)
                .join(', ')
            : 'None',
      },
    ];
  });

  override readonly actions: FormAction[] = [
    {
      label: 'Cancel',
      action: () => {
        this.showModal = false;
      },
      severity: 'secondary',
    },
    {
      label: 'Ok',
      action: (form: FormGroup) => {
        if (form.valid) {
          const formData = form.value;

          // Get IO Type name based on selected ID
          let ioTypeName = '';
          if (this.currentModalType === 'analog') {
            const selectedOption = this.selectOptions?.[
              'analogInputTypes'
            ]?.find((opt) => opt.value === formData.id);
            ioTypeName = selectedOption?.label ?? '';
            formData.ioType = selectedOption?.type ?? '';
            formData.name = formData.name ?? ioTypeName;
          } else if (this.currentModalType === 'temperature') {
            const selectedOption = this.selectOptions?.[
              'temperatureInputTypes'
            ]?.find((opt) => opt.value === formData.id);
            ioTypeName = selectedOption?.label ?? '';
            formData.ioType = selectedOption?.type ?? '';
            formData.name = formData.name ?? ioTypeName;
          }

          // Create new item with name from IO type
          const newItem: AnalogTriggerListItem = {
            id: formData.id,
            data: formData,
            name: ioTypeName,
            description: this.generateDescription(formData),
          };

          // Add new item
          if (this.currentModalType === 'analog') {
            this.analogTriggers.update((triggers) => [...triggers, newItem]);
          } else if (this.currentModalType === 'temperature') {
            this.temperatureTriggers.update((triggers) => [
              ...triggers,
              newItem,
            ]);
          }

          this.showModal = false;
        }
      },
      severity: 'primary',
      disabled: (form?: FormGroup) =>
        !(form?.valid ?? false) || (form?.pristine ?? true),
    },
  ];

  showModal = false;
  ioTypes: IoTypeListItem[] = [];
  modalTitle = '';

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    // Initialize signals from entity data
    effect(() => {
      const asset = this.entity();
      if (asset) {
        // Initialize with asset data
        this.analogTriggers.set(
          (asset.parameters?.analogs || []).map((analog) =>
            this.analogToListItem(analog),
          ),
        );

        this.temperatureTriggers.set(
          (asset.parameters?.temperatures || []).map((temp) =>
            this.temperatureToListItem(temp),
          ),
        );
      }
    });
  }

  ngOnInit(): void {
    this.loadSelectOptions();
  }

  private generateDescription(
    data: AssetAnalogParameter | AssetTemperatureParameter,
  ): string {
    return `Range of ${data.minRange} to ${data.maxRange} with a debounce of ${data.rangeDebounce} positions`;
  }

  private loadSelectOptions() {
    const asset = this.entity();
    if (!isDefined(asset) || !isString(asset.id)) {
      return;
    }
    combineLatest([
      this.loadIOTypes(asset.owner.id, ['analog_input', 'can_input']),
      this.loadIOTypes(asset.owner.id, ['temperature_input']),
    ])
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe(([ioTypes, temperatureIoTypes]) => {
        this.selectOptions = {
          analogInputTypes: ioTypes.items
            .map((item) => ({
              label: item.name ?? '',
              value: item.id,
              type:
                this.apiSchemaService.getEntityType<
                  Record<string, unknown>,
                  IoTypeListItem.TypeEnum
                >(item as Record<string, unknown>, 'IoTypeListItem') ?? '',
            }))
            .sort((a, b) => a.label.localeCompare(b.label)),
          temperatureInputTypes: temperatureIoTypes.items
            .map((item) => ({
              label: item.name ?? '',
              value: item.id,
              type:
                this.apiSchemaService.getEntityType<
                  Record<string, unknown>,
                  IoTypeListItem.TypeEnum
                >(item as Record<string, unknown>, 'IoTypeListItem') ?? '',
            }))
            .sort((a, b) => a.label.localeCompare(b.label)),
        };
        this.selectOptionsLoaded.set(true);
      });
  }

  private loadIOTypes(owner: string, types: string[]) {
    const typePropertyKey = this.apiSchemaService.getTypePropertyKey('IoType');
    const filters = isEmpty(types)
      ? {
          state: {
            value: 'active',
            operator: 'in',
          },
        }
      : {
          state: {
            value: 'active',
            operator: '=',
          },
          [typePropertyKey]: {
            value: types,
            operator: 'in',
          },
        };
    return this.entitiesService
      .listIoTypes(
        owner,
        true,
        0,
        DEFAULT_LIST_SIZE,
        'name',
        this.utilityService.constructRqlFilter(filters),
      )
      .pipe(takeUntilDestroyed(this.destroyRef));
  }

  protected override updateFormFields(): void {
    // No form fields to update in this section
  }

  protected override submitChanges(): void {
    const asset = this.entity();
    if (isNullOrUndefined(asset)) return;

    // Use the prepared data for the API update
    this.handleEntityUpdate(
      this.entitiesService
        .updateAsset(asset.id, {
          parameters: {
            analogs: this.analogTriggers().map((item) => item.data),
            temperatures: this.temperatureTriggers().map((item) => item.data),
          },
        })
        .pipe(takeUntilDestroyed(this.destroyRef)),
      'Asset Analog triggers updated successfully',
    );
  }

  updateAnalogFormFields(): void {
    this.formFields = [
      createDropdownField(
        'id',
        'Analog Input',
        this.selectOptions?.['analogInputTypes'] ?? [],
        '',
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'id',
          props: {
            appendTo: 'body',
          },
        },
      ),
      createNumberField('minRange', 'Min Range', 0, {
        layout: 'horizontal',
        labelWidth: '1/3',
        name: 'minRange',
      }),
      createNumberField('maxRange', 'Max Range', 100, {
        layout: 'horizontal',
        labelWidth: '1/3',
        name: 'maxRange',
      }),
      createNumberField('rangeDebounce', 'Range Debounce', 0, {
        layout: 'horizontal',
        labelWidth: '1/3',
        name: 'rangeDebounce',
      }),
      createNumberField('decValue', 'Drop Amount', 0, {
        layout: 'horizontal',
        labelWidth: '1/3',
        name: 'decValue',
      }),
      createNumberField('incValue', 'Increase Amount', 0, {
        layout: 'horizontal',
        labelWidth: '1/3',
        name: 'incValue',
      }),
    ];
  }

  updateTemperatureFormFields(): void {
    this.formFields = [
      createDropdownField(
        'id',
        'Temperature Input',
        this.selectOptions?.['temperatureInputTypes'] ?? [],
        '',
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'id',
          props: {
            appendTo: 'body',
          },
        },
      ),
      createNumberField('minRange', 'Min Range', 0, {
        layout: 'horizontal',
        labelWidth: '1/3',
        name: 'minRange',
        props: {
          suffix: this.measurementUnitsService.unitSymbol(
            MeasurementUnitType.TEMPERATURE,
          ),
        },
      }),
      createNumberField('maxRange', 'Max Range', 100, {
        layout: 'horizontal',
        labelWidth: '1/3',
        name: 'maxRange',
        props: {
          suffix: this.measurementUnitsService.unitSymbol(
            MeasurementUnitType.TEMPERATURE,
          ),
        },
      }),
      createNumberField('rangeDebounce', 'Range Debounce', 0, {
        layout: 'horizontal',
        labelWidth: '1/3',
        name: 'rangeDebounce',
      }),
    ];
  }

  onClose() {
    this.showModal = false;
  }

  getDescription(
    analog: AssetAnalogParameter | AssetTemperatureParameter,
  ): string {
    return `Range of ${analog.minRange} to ${analog.maxRange} with a debounce of ${analog.rangeDebounce} positions`;
  }

  analogToListItem(analog: AssetAnalogParameter) {
    return {
      id: analog.id,
      name: analog.name,
      description: this.getDescription(analog),
      data: analog,
    };
  }

  temperatureToListItem(temp: AssetTemperatureParameter) {
    return {
      id: temp.id,
      name: temp.name,
      description: this.getDescription(temp),
      data: temp,
    };
  }

  openAnalogModal() {
    this.currentModalType = 'analog';
    this.modalTitle = 'Analog Event Trigger';
    this.updateAnalogFormFields();
    this.showModal = true;
  }

  openTemperatureModal() {
    this.currentModalType = 'temperature';
    this.modalTitle = 'Temperature Event Trigger';
    this.updateTemperatureFormFields();
    this.showModal = true;
  }

  deleteAnalogTrigger(item: AnalogTriggerListItem) {
    this.analogTriggers.update((triggers) => {
      const index = triggers.findIndex((i) => i.id === item.id);
      if (index >= 0) {
        return triggers.filter((_, i) => i !== index);
      }
      return triggers;
    });
  }

  deleteTemperatureTrigger(item: TemperatureTriggerListItem) {
    this.temperatureTriggers.update((triggers) => {
      const index = triggers.findIndex((i) => i.id === item.id);
      if (index >= 0) {
        return triggers.filter((_, i) => i !== index);
      }
      return triggers;
    });
  }
}
