import {
  Component,
  computed,
  effect,
  inject,
  input,
  OnInit,
  signal,
  WritableSignal,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';

import { ButtonModule } from 'primeng/button';
import { InputTextModule } from 'primeng/inputtext';

import {
  EntitiesService,
  DeviceListItem,
  DeviceResponse,
  DeviceCreateRequest,
  SimCardListItem,
  AssetListItem,
} from '../../../../../api';
import { createAutocompleteField } from '../../../../../shared/models';
import { EntitySectionBaseComponent } from '../../base';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import { CommonModule } from '@angular/common';
import { EntityOperationRegistryService } from '../../../services/entity/entity-operation-registry.service';
import {
  debounceTime,
  distinctUntilChanged,
  Observable,
  of,
  Subject,
  switchMap,
} from 'rxjs';
import { UtilityService } from '../../../../../core/services/utility.service';
import { MessageModule } from 'primeng/message';

@Component({
  selector: 'app-device-linked-section',
  imports: [
    CommonModule,
    ButtonModule,
    InputTextModule,
    GridComponent,
    DynamicFormComponent,
    MessageModule,
  ],
  templateUrl: './device-linked-section.component.html',
  styleUrl: './device-linked-section.component.scss',
})
export class DeviceLinkedSectionComponent
  extends EntitySectionBaseComponent<DeviceListItem | DeviceResponse>
  implements OnInit
{
  readonly ownerId = input<string | null>(null);
  readonly entitiesService = inject(EntitiesService);
  private readonly operationRegistry = inject(EntityOperationRegistryService);
  private readonly utilityService = inject(UtilityService);

  readonly deviceLinkedDetails = computed(() => {
    const deviceDetails = this.entity();
    if (!isDefined(deviceDetails)) return [];

    return [
      { key: 'Sim Card', value: deviceDetails.simcard?.name ?? 'None' },
      {
        key: 'Asset',
        value: deviceDetails.asset?.name ?? 'None',
      },
    ];
  });
  private readonly searchSIMCardsSubject = new Subject<string>();
  private readonly searchAssetsSubject = new Subject<string>();
  simCardSuggestions = signal<SimCardListItem[]>([]);
  assetSuggestions = signal<AssetListItem[]>([]);
  protected readonly warning = signal<string | null>(null);

  constructor() {
    super();

    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    effect(() => {
      const deviceDetails = this.entity();
      if (!isDefined(deviceDetails)) return;

      if (deviceDetails.asset) {
        this.checkAssetDevices(deviceDetails);
      }
    });
  }

  ngOnInit(): void {
    this.setupSearch(
      this.searchSIMCardsSubject,
      this.simCardSuggestions,
      this.entitiesService.listSimCards.bind(this.entitiesService),
      { state: 'active' },
    );
    this.setupSearch(
      this.searchAssetsSubject,
      this.assetSuggestions,
      this.entitiesService.listAssets.bind(this.entitiesService),
      { state: 'active' },
    );
  }

  private checkAssetDevices(
    deviceDetails: DeviceListItem | DeviceResponse | undefined,
  ) {
    if (deviceDetails?.asset) {
      this.entitiesService
        .getAsset(deviceDetails.asset.id)
        .subscribe((asset) => {
          if (asset.devices && asset.devices.length > 1) {
            this.warning.set(`Multiple Devices assigned to linked Asset`);
          } else {
            this.warning.set(null);
          }
        });
    } else {
      this.warning.set(null);
    }
  }

  private setupSearch<T>(
    subject: Subject<string>,
    suggestionSignal: WritableSignal<T[]>,
    listMethod: (
      ownerId: string,
      offset: number,
      limit: number,
      orderBy: string,
      filter: string,
    ) => Observable<{ items: T[] }>,
    filters: Record<string, unknown>,
  ) {
    subject
      .pipe(
        debounceTime(300),
        distinctUntilChanged(),
        takeUntilDestroyed(this.destroyRef),
        switchMap((searchTerm) => {
          if (isNullOrUndefined(searchTerm)) {
            return of({ items: [] });
          }
          const rqlFilter = this.utilityService.constructRqlFilter({
            ...filters,
            name: `*${searchTerm}*`,
          });
          return listMethod(
            this.entity()?.owner.id ?? '',
            0,
            10,
            'name',
            rqlFilter,
          );
        }),
      )
      .subscribe((response) => {
        suggestionSignal.set(response.items);
      });
  }

  private searchSIMCards(searchTerm: string) {
    if (isNullOrUndefined(searchTerm)) {
      this.simCardSuggestions.set([]);
      return;
    }

    this.searchSIMCardsSubject.next(searchTerm);
  }

  private searchAssets(searchTerm: string) {
    if (isNullOrUndefined(searchTerm)) {
      this.assetSuggestions.set([]);
      return;
    }

    this.searchAssetsSubject.next(searchTerm);
  }

  protected override updateFormFields(): void {
    const device = this.entity();
    this.formFields = [
      createAutocompleteField(
        'simcard',
        'SIM Card',
        device?.simcard?.name,
        () => this.simCardSuggestions(),
        this.searchSIMCards.bind(this),
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'simcard',
          props: {
            appendTo: 'body',
            showClear: true,
            multiple: false,
            field: 'name',
            completeOnFocus: false,
            typeahead: true,
            showEmptyMessage: true,
          },
        },
      ),
      createAutocompleteField(
        'asset',
        'Asset',
        device?.asset?.name,
        () => this.assetSuggestions(),
        this.searchAssets.bind(this),
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'asset',
          props: {
            appendTo: 'body',
            showClear: true,
            multiple: false,
            field: 'name',
            completeOnFocus: false,
            typeahead: true,
            showEmptyMessage: true,
          },
        },
      ),
    ];
  }

  override getUpdateMethod(): (
    id: string,
    data: Partial<DeviceListItem | DeviceResponse>,
  ) => Observable<DeviceResponse> {
    return (
      this.operationRegistry.getOperation<
        DeviceListItem | DeviceResponse,
        DeviceCreateRequest,
        DeviceResponse,
        'update'
      >('device-config-profile', 'update') ??
      ((id, data) => this.entitiesService.updateDevice(id, data))
    );
  }
}
