import { Injectable, inject } from '@angular/core';
import { Observable, of } from 'rxjs';

import { isNullOrUndefined } from '../../../../shared/utils';
import {
  UserRoleListItem,
  UserRoleResponse,
  AccountsService,
} from '../../../../api';
import {
  DataGridParams,
  EntityDataAdapter,
  GridResponse,
} from '../../../../shared/models';

@Injectable({
  providedIn: 'root',
})
export class UserRolesDataAdapter
  implements EntityDataAdapter<UserRoleListItem, UserRoleResponse>
{
  private readonly accountsService = inject(AccountsService);

  getList(params: DataGridParams): Observable<GridResponse<UserRoleListItem>> {
    const { owner, limit, offset, sortField, filters } = params;

    if (isNullOrUndefined(owner)) {
      return of({ items: [], count: 0 });
    }

    return this.accountsService.listUserRoles(
      owner,
      offset,
      limit,
      sortField as string,
      filters,
    );
  }

  getById(id: string): Observable<UserRoleResponse> {
    return this.accountsService.getUserRole(id);
  }
}
