import {
  ChangeDetectorRef,
  Component,
  OnInit,
  computed,
  effect,
  inject,
  input,
  signal,
} from '@angular/core';
import { Validators } from '@angular/forms';

import { ButtonModule } from 'primeng/button';
import { InputTextModule } from 'primeng/inputtext';
import { faComments } from '@fortawesome/free-solid-svg-icons';
import { FontAwesomeModule } from '@fortawesome/angular-fontawesome';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';

import {
  EntitiesService,
  SmsGatewayProviderCreateRequest,
  SmsGatewayProviderListItem,
  SmsGatewayProviderResponse,
  SmsGatewayProviderTypeListItem,
  SmsGatewayProviderUpdateRequest,
} from '../../../../../api';
import { EntityOperationRegistryService } from '../../../services/entity/entity-operation-registry.service';
import { ApiSchemaService } from '../../../../../core/services/api-schema.service';
import { EntitySectionBaseComponent } from '../../base';

import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import {
  createDropdownField,
  createTextField,
} from '../../../../../shared/models';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import { CommonModule } from '@angular/common';
import { Observable } from 'rxjs';

// Define a local type for what a 'type object' looks like if not imported
interface TypeObjectShape {
  id: string;
  name: string;
  // Add other common properties if they exist across different type objects
  // direction?: string; // Example if direction is common
}

type SmsGatewayProviderEntity =
  | SmsGatewayProviderListItem
  | SmsGatewayProviderCreateRequest;

@Component({
  selector: 'app-sms-gateway-provider-details-section',
  imports: [
    CommonModule,
    ButtonModule,
    InputTextModule,
    GridComponent,
    DynamicFormComponent,
    FontAwesomeModule,
  ],
  templateUrl: './sms-gateway-provider-details-section.component.html',
  styleUrl: './sms-gateway-provider-details-section.component.scss',
})
export class SmsGatewayProviderDetailsSectionComponent
  extends EntitySectionBaseComponent<SmsGatewayProviderEntity>
  implements OnInit
{
  readonly ownerId = input<string | null>(null);
  readonly entitiesService = inject(EntitiesService);
  private readonly operationRegistry = inject(EntityOperationRegistryService);
  private readonly apiSchemaService = inject(ApiSchemaService);
  private readonly cdr = inject(ChangeDetectorRef);

  protected readonly selectOptionsLoaded = signal<boolean>(false);
  private readonly entityName = 'SmsGatewayProvider';

  selectOptions: Record<
    string,
    { label: string; value: string; data: unknown }[]
  > = {};
  faComments = faComments;

  readonly smsGatewayProviderDetails = computed(() => {
    const entity = this.entity();
    if (!isDefined(entity)) return [];

    const typeObject = this.apiSchemaService.getEntityType<
      Record<string, unknown>,
      TypeObjectShape
    >(entity as Record<string, unknown>, this.entityName);

    return [
      {
        key: 'Type',
        value: typeObject?.name ?? 'None',
      },
      { key: 'Name', value: (entity as SmsGatewayProviderListItem).name },
    ];
  });

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    effect(() => {
      const selectOptionsLoaded = this.selectOptionsLoaded();
      if (selectOptionsLoaded) {
        this.updateFormFields();
        this.cdr.detectChanges();
      }
    });
  }

  ngOnInit(): void {
    this.loadSelectOptions();
  }

  private loadSelectOptions(): void {
    const smsGatewayProvider = this.entity();
    const ownerIdValue = this.ownerId();

    const effectiveOwnerId = smsGatewayProvider?.owner?.id ?? ownerIdValue;

    if (isNullOrUndefined(effectiveOwnerId)) {
      this.selectOptions = {};
      this.selectOptionsLoaded.set(true);
      this.updateFormFields();
      return;
    }

    this.entitiesService
      .listSmsGatewayProviderTypes(effectiveOwnerId)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe((result) => {
        this.selectOptions = {
          smsGatewayProviderTypes: result.items
            .map((item) => ({
              label: item?.name,
              value: item.id,
              data: item,
            }))
            .sort((a, b) => a.label.localeCompare(b.label)),
        };

        this.selectOptionsLoaded.set(true);
      });
  }

  protected override updateFormFields(): void {
    const smsGatewayProvider = this.entity();
    const typeObject = this.apiSchemaService.getEntityType<
      Record<string, unknown>,
      TypeObjectShape
    >(smsGatewayProvider as Record<string, unknown>, this.entityName);

    this.formFields = [
      createDropdownField(
        this.apiSchemaService.getTypePropertyKey(this.entityName),
        'Type',
        this.selectOptions?.['smsGatewayProviderTypes'],
        typeObject?.id ?? null,
        {
          name: this.apiSchemaService.getTypePropertyKey(this.entityName),
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: 'Type is required',
            },
          ],

          disabled:
            !this.createMode() &&
            !this.apiSchemaService.usesModernSchema() &&
            isDefined(typeObject) &&
            isDefined(typeObject?.id),
          props: {
            appendTo: 'body',
          },
        },
      ),
      createTextField(
        'name',
        'Name',
        (smsGatewayProvider as SmsGatewayProviderListItem)?.name ?? '',
        {
          name: 'name',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: 'Name is required',
            },
          ],
        },
      ),
    ];
  }

  override getUpdateMethod(): (
    id: string,
    data: Partial<SmsGatewayProviderEntity>,
  ) => Observable<SmsGatewayProviderResponse> {
    return (
      this.operationRegistry.getOperation<
        SmsGatewayProviderEntity,
        SmsGatewayProviderCreateRequest,
        SmsGatewayProviderResponse,
        'update'
      >('sms-gateway-provider', 'update') ??
      ((id, data) =>
        this.entitiesService.updateSmsGatewayProvider(
          id,
          data as SmsGatewayProviderUpdateRequest,
        ))
    );
  }

  protected override onFormValueChange(
    formData: Record<string, string | number | object | undefined | null>,
  ): void {
    const transformedData = { ...formData } as Record<string, unknown>;
    const typePropertyKeyFromForm = this.apiSchemaService.getTypePropertyKey(
      this.entityName,
    );
    const selectedTypeId = transformedData[typePropertyKeyFromForm] as string;

    if (isDefined(selectedTypeId)) {
      const selectedTypeOption = this.selectOptions?.[
        'smsGatewayProviderTypes'
      ]?.find((option) => option.value === selectedTypeId);

      if (
        isDefined(selectedTypeOption) &&
        typeof selectedTypeOption === 'object' &&
        selectedTypeOption !== null
      ) {
        transformedData[typePropertyKeyFromForm] = {
          id: selectedTypeId,
          name:
            (selectedTypeOption.data as SmsGatewayProviderTypeListItem)?.name ??
            '',
        };

        transformedData['direction'] = (
          selectedTypeOption.data as SmsGatewayProviderTypeListItem
        )?.direction;
      }
    }
    this.formValueChange.emit(
      transformedData as Partial<SmsGatewayProviderEntity>,
    );
  }
}
