import { Injectable, inject } from '@angular/core';
import { Observable, of } from 'rxjs';

import { isNullOrUndefined } from '../../../../shared/utils';
import {
  SimCardListItem,
  EntitiesService,
  SimCardResponse,
} from '../../../../api';
import {
  DataGridParams,
  EntityDataAdapter,
  GridResponse,
} from '../../../../shared/models';

@Injectable({
  providedIn: 'root',
})
export class SimCardsDataAdapter
  implements EntityDataAdapter<SimCardListItem, SimCardResponse>
{
  private readonly entitiesService = inject(EntitiesService);

  getList(params: DataGridParams): Observable<GridResponse<SimCardListItem>> {
    const { owner, limit, offset, sortField, filters } = params;

    if (isNullOrUndefined(owner)) {
      return of({ items: [], count: 0 });
    }

    return this.entitiesService.listSimCards(
      owner,
      offset,
      limit,
      sortField as string,
      filters,
    );
  }

  getById(id: string): Observable<SimCardResponse> {
    return this.entitiesService.getSimCard(id);
  }
}
