import { Injectable, inject } from '@angular/core';
import { Observable, of } from 'rxjs';

import { isNullOrUndefined } from '../../../../shared/utils';
import {
  AssetRatingProfileListItem,
  AssetRatingProfileResponse,
  EntitiesService,
} from '../../../../api';
import {
  DataGridParams,
  EntityDataAdapter,
  GridResponse,
} from '../../../../shared/models';

@Injectable({
  providedIn: 'root',
})
export class AssetRatingProfilesDataAdapter
  implements
    EntityDataAdapter<AssetRatingProfileListItem, AssetRatingProfileResponse>
{
  private readonly entitiesService = inject(EntitiesService);

  getList(
    params: DataGridParams,
  ): Observable<GridResponse<AssetRatingProfileListItem>> {
    const { owner, limit, offset, sortField, filters } = params;

    if (isNullOrUndefined(owner)) {
      return of({ items: [], count: 0 });
    }

    return this.entitiesService.listAssetRatingProfiles(
      owner,
      offset,
      limit,
      sortField as string,
      filters,
    );
  }

  getById(id: string): Observable<AssetRatingProfileResponse> {
    return this.entitiesService.getAssetRatingProfile(id);
  }
}
