import { Injectable, inject } from '@angular/core';
import { Observable, of } from 'rxjs';

import { isNullOrUndefined } from '../../../../shared/utils';
import {
  VendorListItem,
  AccountsService,
  VendorResponse,
} from '../../../../api';
import {
  DataGridParams,
  EntityDataAdapter,
  GridResponse,
} from '../../../../shared/models';

@Injectable({
  providedIn: 'root',
})
export class VendorsDataAdapter
  implements EntityDataAdapter<VendorListItem, VendorResponse>
{
  private readonly accountsService = inject(AccountsService);

  getList(params: DataGridParams): Observable<GridResponse<VendorListItem>> {
    const { owner, limit, offset, sortField, filters, counts } = params;

    if (isNullOrUndefined(owner)) {
      return of({ items: [], count: 0 });
    }

    return this.accountsService.listVendors(
      owner,
      offset,
      limit,
      sortField as string,
      filters,
      counts,
    );
  }

  getById(id: string): Observable<VendorResponse> {
    return this.accountsService.getVendor(id);
  }
}
