import {
  AfterViewInit,
  Component,
  computed,
  effect,
  inject,
  signal,
  TemplateRef,
  ViewChild,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { FormGroup, ReactiveFormsModule, Validators } from '@angular/forms';

import { ButtonModule } from 'primeng/button';
import { DataViewModule } from 'primeng/dataview';

import { AssetResponse, Contact, EntitiesService } from '../../../../../api';
import { UtilityService } from '../../../../../core/services/utility.service';
import {
  createTextField,
  createDropdownField,
  FormAction,
} from '../../../../../shared/models';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../base';
import { DynamicFormModalComponent } from '../../../../../shared/components/forms/dynamic-form-modal/dynamic-form-modal.component';
import { PanelModule } from 'primeng/panel';
import { DividerModule } from 'primeng/divider';

@Component({
  selector: 'app-asset-contacts-section',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    ButtonModule,
    DynamicFormModalComponent,
    DataViewModule,
    PanelModule,
    DividerModule,
  ],
  templateUrl: './asset-contacts-section.component.html',
  styleUrl: './asset-contacts-section.component.scss',
})
export class AssetContactsSectionComponent
  extends EntitySectionBaseComponent<AssetResponse>
  implements AfterViewInit
{
  @ViewChild('iconTemplate', { static: true })
  iconTemplate: TemplateRef<unknown> | undefined;
  private readonly entitiesService = inject(EntitiesService);
  readonly utilityService = inject(UtilityService);
  protected readonly selectOptionsLoaded = signal<boolean>(false);

  readonly assetContacts = computed(() => {
    const assetContacts = this.entity()?.contacts;
    if (!isDefined(assetContacts)) return [];

    return assetContacts
      .map((contact) => {
        return [
          { key: contact.type, value: contact.name },
          {
            key: 'mobile',
            value: contact.phoneMobile,
            icon: 'pi pi-mobile',
          },
        ];
      })
      .flat();
  });
  override readonly actions: FormAction[] = [
    {
      label: 'Cancel',
      action: () => {
        this.showModal = false;
      },
      severity: 'secondary',
    },
    {
      label: 'Ok',
      action: (_formData: FormGroup) => {
        return;
      },
      severity: 'primary',
      disabled: (form?: FormGroup) => isNullOrUndefined(form) || form.pristine,
    },
  ];
  contacts: Contact[] = [];
  showModal = false;
  contactTypes = [
    'owner',
    'emergency',
    'administrative',
    'technical',
    'operational',
    'management',
  ];

  constructor() {
    super();

    // React to entity changes
    effect(() => {
      const assetContacts = this.entity()?.contacts;
      if (assetContacts) {
        this.contacts = assetContacts;
        this.updateFormFields();
      }
    });
  }

  ngAfterViewInit(): void {
    this.columns = [
      {
        field: 'key',
        header: '',
        transform: 'uppercase',
        cellTemplate: this.iconTemplate,
      },
      { field: 'value', header: '' },
    ];
  }

  protected override updateFormFields(): void {
    this.formFields = [
      createTextField('name', 'Name', '', {
        name: 'name',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'Name is required',
          },
        ],
      }),
      createDropdownField(
        'type',
        'Type',
        this.contactTypes.map((type) => ({
          label: this.utilityService.toTitleCase(type),
          value: type,
        })),
        '',
        {
          name: 'type',
          props: {
            appendTo: 'body',
          },
        },
      ),
      createTextField('emailAddress', 'Email', '', {
        name: 'emailAddress',
        validations: [
          {
            name: 'email',
            validator: Validators.email,
            message: 'Invalid email format',
          },
        ],
      }),
      createTextField('phoneMobile', 'Mobile', '', {
        name: 'phoneMobile',
      }),
      createTextField('phoneOffice', 'Phone', '', {
        name: 'phoneOffice',
      }),
      createTextField('notes', 'Notes', '', {
        name: 'notes',
      }),
    ];
  }

  protected override submitChanges(
    formData: Record<string, string | number>,
  ): void {
    const asset = this.entity();
    if (isNullOrUndefined(asset)) return;
    this.entitiesService
      .updateAsset(asset.id, formData)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: () => {
          this.isFormEditable.set(false);
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'asset',
            entityId: asset.id,
          });
        },
        error: () => {
          this.isFormEditable.set(true);
        },
      });
  }

  onClose() {
    this.showModal = false;
  }
}
