import { Injectable, inject } from '@angular/core';
import { Observable } from 'rxjs';

import {
  EntitiesService,
  ZoneGroupListItem,
  ZoneGroupListResponse,
  ZoneGroupResponse,
} from '../../../../api';
import { BaseTreeAdapter } from './base-tree.adapter.service';

@Injectable({
  providedIn: 'root',
})
export class GeofenceGroupsDataAdapter extends BaseTreeAdapter<
  ZoneGroupListItem,
  ZoneGroupListResponse,
  ZoneGroupResponse
> {
  private readonly entitiesService = inject(EntitiesService);

  protected fetchEntities(
    owner: string,
    offset: number | undefined,
    limit: number | undefined,
    sortField: string | undefined,
    filters: string,
  ): Observable<ZoneGroupListResponse> {
    return this.entitiesService.listZoneGroups(
      owner,
      offset,
      limit,
      sortField,
      filters,
    );
  }

  getById(id: string): Observable<ZoneGroupResponse> {
    return this.entitiesService.getZoneGroup(id);
  }
}
