import { Injectable, inject } from '@angular/core';
import { Observable, of } from 'rxjs';

import { isNullOrUndefined } from '../../../../shared/utils';
import {
  AssetStateProfileListItem,
  AssetStateProfileResponse,
  EntitiesService,
} from '../../../../api';
import {
  DataGridParams,
  EntityDataAdapter,
  GridResponse,
} from '../../../../shared/models';

@Injectable({
  providedIn: 'root',
})
export class AssetStateProfilesDataAdapter
  implements
    EntityDataAdapter<AssetStateProfileListItem, AssetStateProfileResponse>
{
  private readonly entitiesService = inject(EntitiesService);

  getList(
    params: DataGridParams,
  ): Observable<GridResponse<AssetStateProfileListItem>> {
    const { owner, limit, offset, sortField, filters } = params;

    if (isNullOrUndefined(owner)) {
      return of({ items: [], count: 0 });
    }

    return this.entitiesService.listAssetStateProfiles(
      owner,
      offset,
      limit,
      sortField as string,
      filters,
    );
  }

  getById(id: string): Observable<AssetStateProfileResponse> {
    return this.entitiesService.getAssetStateProfile(id);
  }
}
