import { Injectable, inject } from '@angular/core';
import { Observable, of } from 'rxjs';

import { isNullOrUndefined } from '../../../../shared/utils';
import {
  DeviceListItem,
  DeviceResponse,
  EntitiesService,
} from '../../../../api';
import {
  DataGridParams,
  GridDataService,
  GridResponse,
} from '../../../../shared/models';

@Injectable({
  providedIn: 'root',
})
export class DevicesDataAdapter implements GridDataService<DeviceListItem> {
  private readonly entitiesService = inject(EntitiesService);

  getList(params: DataGridParams): Observable<GridResponse<DeviceListItem>> {
    const { owner, limit, offset, sortField, filters } = params;

    if (isNullOrUndefined(owner)) {
      return of({ items: [], count: 0 });
    }

    return this.entitiesService.listDevices(
      owner,
      offset,
      limit,
      sortField as string,
      filters,
    );
  }

  getById(id: string): Observable<DeviceResponse> {
    return this.entitiesService.getDevice(id);
  }
}
