import { Injectable, inject } from '@angular/core';
import { Observable } from 'rxjs';

import { EntitiesService, AssetCategoryResponse } from '../../../../api';
import { BaseTreeAdapter } from './base-tree.adapter.service';

@Injectable({
  providedIn: 'root',
})
export class AssetCategoriesDataAdapter extends BaseTreeAdapter<
  AssetCategoryResponse,
  { items: AssetCategoryResponse[]; count: number }
> {
  private readonly entitiesService = inject(EntitiesService);

  protected fetchEntities(
    owner: string,
    offset: number | undefined,
    limit: number | undefined,
    sortField: string | undefined,
    filters: string,
  ): Observable<{ items: AssetCategoryResponse[]; count: number }> {
    return this.entitiesService.listAssetCategories(
      owner,
      offset,
      limit,
      sortField,
      filters,
    );
  }

  getById(id: string): Observable<AssetCategoryResponse> {
    return this.entitiesService.getAssetCategory(id);
  }
}
