import { CommonModule } from '@angular/common';
import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  output,
  signal,
  effect,
} from '@angular/core';
import { AccordionModule } from 'primeng/accordion';
import { ButtonModule } from 'primeng/button';
import { DividerModule } from 'primeng/divider';
import { TooltipModule } from 'primeng/tooltip';
import { AdminDetailSection } from '../../models';
import { isDefined, isNullOrUndefined } from '../../../../shared/utils';

@Component({
  selector: 'app-details-accordion-container',
  imports: [
    CommonModule,
    AccordionModule,
    DividerModule,
    ButtonModule,
    TooltipModule,
  ],
  templateUrl: './details-accordion-container.component.html',
  styleUrl: './details-accordion-container.component.scss',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class DetailsAccordionContainerComponent {
  readonly sections = input<AdminDetailSection[]>([]);
  readonly entity = input<unknown>(null);
  readonly title = input<string>('Details');
  readonly subtitle = input<string>('');
  readonly allowModeToggle = input<boolean>(true);
  readonly initialMode = input<'view' | 'edit'>('view');
  entityChange = output<unknown>();

  // Accordion state management to preserve expansion state during data updates
  readonly accordionValue = signal<string[]>(['information']);
  private readonly _sectionInputsCache = new Map<
    string,
    Record<string, unknown>
  >();

  constructor() {
    // Monitor entity changes and preserve accordion state
    effect(() => {
      this.entity(); // Track entity changes
      const sections = this.sections(); // Track sections changes

      // Clear cache when sections change to avoid stale references
      this._clearStaleCache(sections);
    });
  }

  /**
   * Clear cache entries for sections that no longer exist
   */
  private _clearStaleCache(currentSections: AdminDetailSection[]): void {
    const currentSectionIds = new Set(currentSections.map((s) => s.id));
    const cacheKeys = Array.from(this._sectionInputsCache.keys());

    for (const key of cacheKeys) {
      const sectionId = key.replace('_inputs', '');
      if (!currentSectionIds.has(sectionId)) {
        this._sectionInputsCache.delete(key);
      }
    }
  }

  /**
   * Handle accordion panel open/close events
   */
  onAccordionChange(value: string | number | string[] | number[]): void {
    const normalizedValue = Array.isArray(value)
      ? value.map(String)
      : [String(value)];
    this.accordionValue.set(normalizedValue);
  }

  // Computed properties for sections by category
  readonly informationSections = computed(() =>
    this.visibleSections()
      .filter(
        (s) => s.category === 'information' || isNullOrUndefined(s.category),
      )
      .sort((a, b) => (a.order ?? 0) - (b.order ?? 0)),
  );

  readonly settingsSections = computed(() =>
    this.visibleSections()
      .filter((s) => s.category === 'settings')
      .sort((a, b) => (a.order ?? 0) - (b.order ?? 0)),
  );

  readonly statisticsSections = computed(() =>
    this.visibleSections()
      .filter((s) => s.category === 'statistics')
      .sort((a, b) => (a.order ?? 0) - (b.order ?? 0)),
  );

  readonly eventsSections = computed(() =>
    this.visibleSections()
      .filter((s) => s.category === 'events')
      .sort((a, b) => (a.order ?? 0) - (b.order ?? 0)),
  );

  readonly customSections = computed(() =>
    this.visibleSections()
      .filter((s) => s.category === 'custom')
      .sort((a, b) => (a.order ?? 0) - (b.order ?? 0)),
  );

  readonly ioSections = computed(() =>
    this.visibleSections()
      .filter((s) => s.category === 'io')
      .sort((a, b) => (a.order ?? 0) - (b.order ?? 0)),
  );

  readonly accessoriesSections = computed(() =>
    this.visibleSections()
      .filter((s) => s.category === 'accessories')
      .sort((a, b) => (a.order ?? 0) - (b.order ?? 0)),
  );

  readonly feedSections = computed(() =>
    this.visibleSections()
      .filter((s) => s.category === 'feed')
      .sort((a, b) => (a.order ?? 0) - (b.order ?? 0)),
  );

  readonly controlsSections = computed(() =>
    this.visibleSections()
      .filter((s) => s.category === 'controls')
      .sort((a, b) => (a.order ?? 0) - (b.order ?? 0)),
  );

  readonly assetsSections = computed(() =>
    this.visibleSections()
      .filter((s) => s.category === 'assets')
      .sort((a, b) => (a.order ?? 0) - (b.order ?? 0)),
  );

  readonly usersSections = computed(() =>
    this.visibleSections()
      .filter((s) => s.category === 'users')
      .sort((a, b) => (a.order ?? 0) - (b.order ?? 0)),
  );

  readonly featureSections = computed(() =>
    this.visibleSections()
      .filter((s) => s.category === 'features')
      .sort((a, b) => (a.order ?? 0) - (b.order ?? 0)),
  );

  readonly visibleSections = computed(() => {
    return this.sections().filter((section) => {
      if (typeof section.visible === 'function') {
        return section.visible(this.entity()) === true;
      }
      return section.visible !== false;
    });
  });

  sectionTypes = signal([
    { key: 'information', label: 'Information' },
    { key: 'settings', label: 'Settings' },
    { key: 'events', label: 'Events' },
    { key: 'statistics', label: 'Statistics' },
    { key: 'io', label: 'IO' },
    { key: 'accessories', label: 'Accessories' },
    { key: 'controls', label: 'Controls' },
    { key: 'assets', label: 'Assets' },
    { key: 'users', label: 'Users' },
    { key: 'features', label: 'Features' },
    { key: 'feed', label: 'Changes' },
    { key: 'custom', label: 'Custom' },
  ]);

  // Generic method to get sections by type
  getSections(type: string) {
    switch (type) {
      case 'information':
        return this.informationSections();
      case 'settings':
        return this.settingsSections();
      case 'events':
        return this.eventsSections();
      case 'statistics':
        return this.statisticsSections();
      case 'io':
        return this.ioSections();
      case 'accessories':
        return this.accessoriesSections();
      case 'controls':
        return this.controlsSections();
      case 'feed':
        return this.feedSections();
      case 'custom':
        return this.customSections();
      case 'assets':
        return this.assetsSections();
      case 'users':
        return this.usersSections();
      case 'features':
        return this.featureSections();
      default:
        return [];
    }
  }

  // Generic method to check if a section type has items
  hasSections(type: string): boolean {
    const sections = this.getSections(type);
    return isDefined(sections) && sections.length > 0;
  }

  getSectionInputs(section: AdminDetailSection): Record<string, unknown> {
    // Create a stable input object to prevent unnecessary component recreation
    // Only create new object if the section inputs have actually changed
    const key = `${section.id}_inputs`;

    const currentInputs = {
      ...section.componentInputs,
      onEntityChange: (updatedEntity: unknown) => {
        this.entityChange.emit(updatedEntity);
      },
    };

    const cachedInputs = this._sectionInputsCache.get(key);

    if (!cachedInputs || this._hasInputsChanged(cachedInputs, currentInputs)) {
      this._sectionInputsCache.set(key, currentInputs);
      return currentInputs;
    }

    return cachedInputs;
  }

  private _hasInputsChanged(
    oldInputs: Record<string, unknown>,
    newInputs: Record<string, unknown>,
  ): boolean {
    const oldKeys = Object.keys(oldInputs).filter(
      (k) => k !== 'onEntityChange',
    );
    const newKeys = Object.keys(newInputs).filter(
      (k) => k !== 'onEntityChange',
    );

    if (oldKeys.length !== newKeys.length) return true;

    return oldKeys.some((key) => oldInputs[key] !== newInputs[key]);
  }
}
