import { Injectable, inject } from '@angular/core';
import { Observable, of } from 'rxjs';

import { isNullOrUndefined } from '../../../../shared/utils';
import {
  ClientListItem,
  ClientResponse,
  AccountsService,
} from '../../../../api';
import {
  DataGridParams,
  EntityDataAdapter,
  GridResponse,
} from '../../../../shared/models';

@Injectable({
  providedIn: 'root',
})
export class ClientsDataAdapter
  implements EntityDataAdapter<ClientListItem, ClientResponse>
{
  private readonly accountsService = inject(AccountsService);

  /**
   * Retrieves a list of clients
   * @param params Grid parameters (requires owner to be specified)
   * @returns Observable of client list response
   */
  getList(params: DataGridParams): Observable<GridResponse<ClientListItem>> {
    const { owner, limit, offset, sortField, filters, counts } = params;

    if (isNullOrUndefined(owner)) {
      return of({ items: [], count: 0 });
    }

    return this.accountsService.listClients(
      owner,
      offset,
      limit,
      sortField as string,
      filters,
      counts,
    );
  }

  getById(id: string): Observable<ClientResponse> {
    return this.accountsService.getClient(id);
  }
}
