import { Injectable, inject } from '@angular/core';
import { Observable, of } from 'rxjs';

import { isNullOrUndefined } from '../../../../shared/utils';
import { EntitiesService, ZoneListItem, ZoneResponse } from '../../../../api';
import {
  DataGridParams,
  EntityDataAdapter,
  GridResponse,
} from '../../../../shared/models';

@Injectable({
  providedIn: 'root',
})
export class GeofencesDataAdapter
  implements EntityDataAdapter<ZoneListItem, ZoneResponse>
{
  private readonly entitiesService = inject(EntitiesService);

  getList(params: DataGridParams): Observable<GridResponse<ZoneListItem>> {
    const { owner, limit, offset, sortField, filters } = params;

    if (isNullOrUndefined(owner)) {
      return of({ items: [], count: 0 });
    }

    return this.entitiesService.listZones(
      owner,
      offset,
      limit,
      sortField as string,
      filters,
    );
  }

  getById(id: string): Observable<ZoneResponse> {
    return this.entitiesService.getZone(id);
  }
}
