import { Component, computed, inject, input, signal } from '@angular/core';

import { MessageModule } from 'primeng/message';
import { ProgressSpinnerModule } from 'primeng/progressspinner';

import {
  AlertListItem,
  EntitiesService,
  AlertResponse,
  AlertCreateRequest,
} from '../../../../../api';
import { isNullOrUndefined } from '../../../../../shared/utils';
import { EntityDetailsStateService } from '../../../services/entity/entity-details.state.service';
import { EntityOperationRegistryService } from '../../../services/entity/entity-operation-registry.service';
import { DetailsAccordionContainerComponent } from '../../details-accordion-container/details-accordion-container.component';
import { AlertSectionConfigFactory } from '../../../factories';

@Component({
  selector: 'app-alert-details-container',
  imports: [
    DetailsAccordionContainerComponent,
    ProgressSpinnerModule,
    MessageModule,
  ],
  templateUrl: './alert-details-container.component.html',
  styleUrl: './alert-details-container.component.scss',
})
export class AlertDetailsContainerComponent {
  readonly entity = input<AlertListItem | null>(null);

  private readonly alertSectionFactory = inject(AlertSectionConfigFactory);
  readonly entityDetailsState = inject(EntityDetailsStateService);
  private readonly entitiesService = inject(EntitiesService);
  private readonly operationRegistry = inject(EntityOperationRegistryService);

  readonly isLoading = computed(() => this.entityDetailsState.isLoading());
  readonly isSoftRefreshing = computed(() =>
    this.entityDetailsState.isSoftRefreshing(),
  );
  readonly isInitialLoading = computed(
    () => this.isLoading() && !this.isSoftRefreshing() && !this.fullAlert(),
  );
  readonly fullAlert = computed(() => {
    const entityDetails = this.entityDetailsState.selectedItem();

    if (isNullOrUndefined(entityDetails)) {
      return null;
    }
    return entityDetails as AlertResponse;
  });
  readonly sections = computed(() => {
    const alert = this.fullAlert();
    if (isNullOrUndefined(alert)) return [];
    return this.alertSectionFactory.createAllAlertSections(alert);
  });
  readonly error = signal<string | null>(null);

  constructor() {
    this.operationRegistry.registerEntityOperations('alert', {
      update: (id, data) => this.entitiesService.updateAlert(id, data),
      create: (data: AlertCreateRequest) =>
        this.entitiesService.createAlert(data),
      get: (id) => this.entitiesService.getAlert(id),
    });
  }

  onEntityChange(entity: unknown): void {
    this.entityDetailsState.updateEntity(entity as AlertResponse);
    this.error.set(null);
  }
}
