// Angular imports
import {
  Component,
  computed,
  effect,
  inject,
  input,
  signal,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormGroup, FormsModule, ReactiveFormsModule } from '@angular/forms';

// Third-party imports
import { InputTextModule } from 'primeng/inputtext';
import { ButtonModule } from 'primeng/button';
import { PanelModule } from 'primeng/panel';
import { SelectChangeEvent, SelectModule } from 'primeng/select';

// Application imports
import {
  DeviceCreateRequest,
  DeviceIOParameters,
  DeviceResponse,
  DeviceTypeResponse,
  EntitiesService,
  IoTypeListItem,
} from '../../../../../api';
import { UtilityService } from '../../../../../core/services/utility.service';
import { ApiSchemaService } from '../../../../../core/services/api-schema.service';
import { FormAction } from '../../../../../shared/models';
import { DynamicFormModalComponent } from '../../../../../shared/components/forms/dynamic-form-modal/dynamic-form-modal.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import {
  addCalibrationParams,
  calculateIoChanges,
  clearIOConfiguration,
  formatIoSummary,
  generateFormFields,
  getCustomInputs,
  getDefaultCalibration,
  getDeviceIOWhitelist,
  getIoKeys,
  getIoTypeDisplayName,
  IODeviceConfig,
  updateIOValues,
} from '../../../helpers';
import { DeviceEntity, IO_TYPE_MAP } from '../../../models';
import {
  isDefined,
  isNullOrUndefined,
  setNestedProperty,
} from '../../../../../shared/utils';
import { Observable } from 'rxjs';
import { EntityOperationRegistryService } from '../../../services/entity/entity-operation-registry.service';
import { EntitySectionBaseComponent } from '../../base';

@Component({
  selector: 'app-device-io-section',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    ButtonModule,
    InputTextModule,
    PanelModule,
    DynamicFormModalComponent,
    GridComponent,
    FormsModule,
    SelectModule,
  ],
  templateUrl: './device-io-section.component.html',
  styleUrl: './device-io-section.component.scss',
})
export class DeviceIOSectionComponent extends EntitySectionBaseComponent<DeviceEntity> {
  readonly ioType = input.required<keyof DeviceIOParameters>();
  readonly deviceType = input.required<DeviceTypeResponse | null>();
  readonly ioTypes = input.required<IoTypeListItem[]>();
  readonly iconType = input.required<'svg' | 'primeng'>();
  readonly iconName = input.required<string>();
  readonly utilityService = inject(UtilityService);
  readonly entitiesService = inject(EntitiesService);
  private readonly operationRegistry = inject(EntityOperationRegistryService);
  private readonly apiSchemaService = inject(ApiSchemaService);

  // Modal-related signals
  readonly selectedInputName = signal<string | null>(null);
  readonly selectedInputId = signal<string>('');
  readonly selectedInputUnit = signal<string | undefined>(undefined);
  readonly calibrationData = signal<IODeviceConfig | null>(null);
  readonly showModal = signal<boolean>(false);

  // Device-related signals
  readonly ioValues = signal<DeviceIOParameters>({});

  // IO type mapping
  readonly ioTypeMap: { [K in keyof DeviceIOParameters]: string } = IO_TYPE_MAP;

  // Modal actions
  override readonly actions: FormAction[] = [
    {
      label: 'Cancel',
      action: () => {
        this.showModal.set(false);
      },
      severity: 'secondary',
    },
    {
      label: 'Ok',
      action: (formGroup: FormGroup) => {
        if (formGroup.valid) {
          this.applyCalibration(formGroup);
        }
      },
      severity: 'primary',
      disabled: (form?: FormGroup) => isNullOrUndefined(form),
    },
  ];

  // Summary of I/O configuration for view mode
  readonly ioSummary = computed(() =>
    formatIoSummary(this.filteredIoTypes(), this.ioValues(), this.ioType()),
  );

  readonly filteredIoTypes = computed(() => {
    const currentIoType = this.ioType();
    return this.ioTypes()
      .filter((x) => {
        const typeValue = this.apiSchemaService.getEntityType<
          Record<string, unknown>,
          string
        >(x as Record<string, unknown>, 'IoTypeListItem');
        return x.state === 'active' && typeValue === currentIoType;
      })
      .sort((a, b) => (a.name ?? '').localeCompare(b.name ?? ''));
  });

  readonly getDisplayName = (ioType: keyof DeviceIOParameters | string) =>
    getIoTypeDisplayName(ioType, this.ioTypeMap);
  private originalIoValues: DeviceIOParameters | null = null;

  constructor() {
    super();

    this.columns = [
      { field: 'key', header: 'Mode', transform: 'uppercase' },
      { field: 'value', header: 'Configuration' },
    ];

    effect(() => {
      const device = this.entity();
      if (device) {
        this.ioValues.set(updateIOValues(device));
      }
    });
  }

  override getUpdateMethod(): (
    id: string,
    data: Partial<DeviceEntity>,
  ) => Observable<DeviceResponse> {
    return (
      this.operationRegistry.getOperation<
        DeviceEntity,
        DeviceCreateRequest,
        DeviceResponse,
        'update'
      >('device', 'update') ??
      ((id, data) => this.entitiesService.updateDevice(id, data))
    );
  }

  override transformFormData(
    formData: Record<string, string | boolean>,
  ): Partial<DeviceEntity> {
    const result = {};
    if (this.injectDataAtPath()) {
      setNestedProperty(result, this.dataPath(), formData);
    } else {
      Object.assign(result, formData);
    }

    return result;
  }

  getSelectedConfigOption(inputId: string): string {
    const currentIoType = this.ioType();

    if (isNullOrUndefined(currentIoType)) {
      return 'none';
    }

    const ioConfig = this.ioValues()[currentIoType]?.[inputId];

    if (isDefined(ioConfig)) {
      return ioConfig.input ?? inputId;
    }

    const device = this.entity();
    const defaultValue =
      device?.parameters?.['default_inputs']?.[currentIoType]?.[inputId];

    if (isDefined(defaultValue)) {
      return defaultValue;
    }

    return 'none';
  }

  // #region Modal related methods
  protected override updateFormFields(): void {
    const calibration = this.calibrationData();
    const currentIoType = this.ioType();
    if (!calibration) return;

    this.formFields = generateFormFields(
      currentIoType,
      calibration,
      this.deviceType(),
      this.selectedInputUnit(),
    );
  }

  openCalibrationModal(
    inputId: string,
    currentValue: IODeviceConfig | null,
    typeName: string | null | undefined,
    unit?: string | null,
  ): void {
    const currentIoType = this.ioType();

    if (isNullOrUndefined(currentIoType)) {
      return;
    }

    this.selectedInputName.set(typeName ?? '');
    this.selectedInputId.set(inputId);
    this.selectedInputUnit.set(unit ?? undefined);

    const isCustomInput = inputId === '_custom_';

    let calibrationData = currentValue;
    if (isNullOrUndefined(calibrationData)) {
      calibrationData = getDefaultCalibration(currentIoType);
    }

    if (isCustomInput) {
      calibrationData.input = '';
    } else {
      calibrationData.input = calibrationData.input ?? inputId;
    }

    this.calibrationData.set(calibrationData);
    this.updateFormFields();
    this.showModal.set(true);
  }

  applyCalibration(formGroup: FormGroup): void {
    const currentIoType = this.ioType();
    const originalInputId = this.selectedInputId();

    if (isNullOrUndefined(originalInputId)) return;

    const newInputName = formGroup.get('input')?.value;

    const newCalibration = {
      input: newInputName,
    };

    addCalibrationParams(newCalibration, currentIoType, formGroup);

    const currentValues = this.ioValues();
    if (isNullOrUndefined(currentValues[currentIoType])) {
      currentValues[currentIoType] = {};
    }

    if (isDefined(currentValues[currentIoType][originalInputId])) {
      currentValues[currentIoType][originalInputId] = {
        ...currentValues[currentIoType][originalInputId],
        ...newCalibration,
      };
    } else {
      currentValues[currentIoType][originalInputId] = newCalibration;
    }

    this.ioValues.set({ ...currentValues });
    this.showModal.set(false);
  }
  //#endregion

  //#region  State management methods
  protected override onEdit(): void {
    this.originalIoValues = JSON.parse(JSON.stringify(this.ioValues()));
    this.isFormEditable.set(true);
  }

  cancelEdit(): void {
    if (this.originalIoValues) {
      this.ioValues.set({ ...this.originalIoValues }); // Restore the original state
    }
    this.isFormEditable.set(false);
  }

  private getIoChanges(): Partial<DeviceIOParameters> {
    return calculateIoChanges(this.ioValues(), this.originalIoValues);
  }

  saveIOChanges(): void {
    const changes = this.getIoChanges();
    this.submitChanges(changes);
  }

  //#endregion

  //#region IO related methods
  handleConfigChange(
    event: SelectChangeEvent,
    inputId: string,
    typeName: string | null | undefined,
    unit?: string | null,
  ): void {
    const selectedValue = event.value;
    const currentIoType = this.ioType();

    if (isNullOrUndefined(currentIoType)) {
      return;
    }

    if (selectedValue === 'none') {
      this.ioValues.set(
        clearIOConfiguration(this.ioValues(), this.ioType(), inputId),
      );
    } else if (selectedValue === '_custom_') {
      this.openCalibrationModal('_custom_', null, typeName, unit);
    } else {
      let currentConfig = this.ioValues()[currentIoType]?.[inputId];

      if (isNullOrUndefined(currentConfig)) {
        currentConfig = getDefaultCalibration(currentIoType);
        currentConfig.input = selectedValue;

        const currentValues = this.ioValues();
        if (isNullOrUndefined(currentValues[currentIoType])) {
          currentValues[currentIoType] = {};
        }
        currentValues[currentIoType][inputId] = currentConfig;
        this.ioValues.set({ ...currentValues });
      } else if (currentConfig.input !== selectedValue) {
        currentConfig.input = selectedValue;

        const currentValues = this.ioValues();
        currentValues[currentIoType][inputId] = { ...currentConfig };
        this.ioValues.set({ ...currentValues });
      }

      if (selectedValue !== inputId) {
        this.openCalibrationModal(inputId, currentConfig, typeName, unit);
      }
    }
  }

  getLookupValues(
    customInputs: string[] = [],
  ): { label: string; value: string }[] {
    const deviceType = this.deviceType();
    const currentIoType = this.ioType();
    const device = this.entity();

    if (isNullOrUndefined(currentIoType) || !deviceType || !device) {
      return [{ label: 'None', value: 'none' }];
    }

    const inputs = getDeviceIOWhitelist(deviceType, device, currentIoType);

    const existingCustomInputs = getCustomInputs(
      this.ioValues(),
      this.ioType(),
      inputs,
    );

    const allCustomInputs = [...customInputs, ...existingCustomInputs];

    return [
      { label: 'None', value: 'none' },
      ...inputs
        .map((key) => ({ label: key, value: key }))
        .sort((a, b) => a.label.localeCompare(b.label)),
      ...allCustomInputs
        .filter((x) => !inputs.includes(x))
        .map((key) => ({ label: key, value: key })),
      { label: 'Custom...', value: '_custom_' },
    ];
  }

  getIoKeys(deviceType: DeviceTypeResponse | null): string[] {
    if (!deviceType) return [];
    const currentIoType = this.ioType();
    const device = this.entity();

    return getIoKeys(deviceType, device, true, [currentIoType]);
  }
  //#endregion
}
