import { Injectable, inject } from '@angular/core';
import { Observable } from 'rxjs';

import { EntitiesService, AssetGroupResponse } from '../../../../api';
import { BaseTreeAdapter } from './base-tree.adapter.service';

@Injectable({
  providedIn: 'root',
})
export class AssetGroupsDataAdapter extends BaseTreeAdapter<
  AssetGroupResponse,
  { items: AssetGroupResponse[]; count: number }
> {
  private readonly entitiesService = inject(EntitiesService);

  protected fetchEntities(
    owner: string,
    offset: number | undefined,
    limit: number | undefined,
    sortField: string | undefined,
    filters: string,
  ): Observable<{ items: AssetGroupResponse[]; count: number }> {
    return this.entitiesService.listAssetGroups(
      owner,
      offset,
      limit,
      sortField,
      filters,
    );
  }

  getById(id: string): Observable<AssetGroupResponse> {
    return this.entitiesService.getAssetGroup(id);
  }
}
