import { Component, computed, inject, input, signal } from '@angular/core';

import { MessageModule } from 'primeng/message';
import { ProgressSpinnerModule } from 'primeng/progressspinner';

import { DetailsAccordionContainerComponent } from '../../details-accordion-container/details-accordion-container.component';
import {
  AssetCategoryCreateRequest,
  AssetCategoryResponse,
  EntitiesService,
} from '../../../../../api';
import { AssetCategorySectionConfigFactory } from '../../../factories';
import { EntityDetailsStateService } from '../../../services/entity/entity-details.state.service';
import { EntityOperationRegistryService } from '../../../services/entity/entity-operation-registry.service';

@Component({
  selector: 'app-asset-category-details-container',
  imports: [
    DetailsAccordionContainerComponent,
    ProgressSpinnerModule,
    MessageModule,
  ],
  templateUrl: './asset-category-details-container.component.html',
  styleUrl: './asset-category-details-container.component.scss',
})
export class AssetCategoryDetailsContainerComponent {
  readonly entity = input<AssetCategoryResponse | null>(null);

  private readonly assetCategorySectionFactory = inject(
    AssetCategorySectionConfigFactory,
  );
  readonly entityDetailsState = inject(EntityDetailsStateService);
  private readonly entitiesService = inject(EntitiesService);
  private readonly operationRegistry = inject(EntityOperationRegistryService);

  readonly isLoading = computed(() => this.entityDetailsState.isLoading());
  readonly isSoftRefreshing = computed(() =>
    this.entityDetailsState.isSoftRefreshing(),
  );
  readonly isInitialLoading = computed(
    () =>
      this.isLoading() && !this.isSoftRefreshing() && !this.fullAssetCategory(),
  );
  readonly fullAssetCategory = computed(() => {
    const entityDetails = this.entityDetailsState.selectedItem();

    if (!entityDetails) {
      return null;
    }
    return entityDetails as AssetCategoryResponse;
  });
  readonly sections = computed(() => {
    const assetCategory = this.fullAssetCategory();
    if (!assetCategory) return [];
    return this.assetCategorySectionFactory.createAllAssetCategorySections(
      assetCategory,
    );
  });
  readonly error = signal<string | null>(null);

  constructor() {
    this.operationRegistry.registerEntityOperations('asset-category', {
      update: (id, data) => this.entitiesService.updateAssetCategory(id, data),
      create: (data: AssetCategoryCreateRequest) =>
        this.entitiesService.createAssetCategory(data),
      get: (id) => this.entitiesService.getAssetCategory(id),
    });
  }

  onEntityChange(entity: unknown): void {
    this.entityDetailsState.updateEntity(entity as AssetCategoryResponse);
    this.error.set(null);
  }
}
