import { Injectable, inject } from '@angular/core';
import { Observable, of } from 'rxjs';

import { isNullOrUndefined } from '../../../../shared/utils';
import {
  DistributorListItem,
  DistributorResponse,
  AccountsService,
} from '../../../../api';
import {
  DataGridParams,
  EntityDataAdapter,
  GridResponse,
} from '../../../../shared/models';

@Injectable({
  providedIn: 'root',
})
export class DistributorsDataAdapter
  implements EntityDataAdapter<DistributorListItem, DistributorResponse>
{
  private readonly accountsService = inject(AccountsService);

  /**
   * Retrieves a list of distributors
   * @param params Grid parameters (requires owner to be specified)
   * @returns Observable of distributor list response
   */
  getList(
    params: DataGridParams,
  ): Observable<GridResponse<DistributorListItem>> {
    const { owner, limit, offset, sortField, filters, counts } = params;

    if (isNullOrUndefined(owner)) {
      return of({ items: [], count: 0 });
    }

    return this.accountsService.listDistributors(
      owner,
      offset,
      limit,
      sortField as string,
      filters,
      counts,
    );
  }

  getById(id: string): Observable<DistributorResponse> {
    return this.accountsService.getDistributor(id);
  }
}
