import { CommonModule } from '@angular/common';
import {
  ChangeDetectorRef,
  Component,
  computed,
  effect,
  inject,
  input,
  OnInit,
  signal,
} from '@angular/core';
import { ReactiveFormsModule, Validators } from '@angular/forms';
import { ButtonModule } from 'primeng/button';
import { InputTextModule } from 'primeng/inputtext';
import { ChipModule } from 'primeng/chip';

import { EntitySectionBaseComponent } from '../../../components/base/entity-section-base';
import {
  AssetCreateRequest,
  AssetListItem,
  AssetTagListItem,
  EntitiesService,
} from '../../../../../api';
import {
  hasProperty,
  isDefined,
  isEmpty,
  isNullOrUndefined,
} from '../../../../../shared/utils';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { UtilityService } from '../../../../../core/services/utility.service';
import {
  AssetGroupingTreeItem,
  createAutocompleteField,
  createDropdownField,
  createMultiselectField,
  createTextField,
  createTreeSelectField,
} from '../../../../../shared/models';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import {
  catchError,
  combineLatest,
  debounceTime,
  distinctUntilChanged,
  firstValueFrom,
  of,
  Subject,
  switchMap,
} from 'rxjs';
import { COLORS } from '../../../../../core/models';
import { SEARCH_DEBOUNCE_TIME } from '../../../../users/profile/profile.component';
import { AssetGroupingService } from '../../../../../shared/services/asset-grouping.service';
import { TreeNode } from 'primeng/api';

@Component({
  selector: 'app-asset-details-section',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    ButtonModule,
    InputTextModule,
    ChipModule,
    GridComponent,
    DynamicFormComponent,
  ],
  templateUrl: './asset-details-section.component.html',
  styleUrl: './asset-details-section.component.scss',
})
export class AssetDetailsSectionComponent
  extends EntitySectionBaseComponent<AssetListItem | AssetCreateRequest>
  implements OnInit
{
  readonly ownerId = input<string | null>(null);
  private readonly entitiesService = inject(EntitiesService);
  private readonly utilityService = inject(UtilityService);
  private readonly assetGroupingService = inject(AssetGroupingService);
  protected readonly selectOptionsLoaded = signal<boolean>(false);
  assetTypes: { label: string; value: string }[] = [];
  selectOptions: Record<
    string,
    { label: string; value: string }[] | AssetGroupingTreeItem[]
  > = {};
  colors = [...COLORS]
    .sort((a, b) => a.localeCompare(b))
    .map((color) => ({
      label: this.utilityService.toTitleCase(color),
      value: color,
    }));
  readonly assetDetails = computed(() => {
    const assetDetails = this.entity();
    if (!isDefined(assetDetails)) return [];

    return [
      {
        key: 'Name',
        value: assetDetails.name,
      },
      {
        key: 'Tags',
        value: !isEmpty(assetDetails.tags)
          ? assetDetails?.tags?.map((tag) => tag).join(', ')
          : 'None',
      },
      {
        key: 'Type',
        value: isDefined(assetDetails.assetType)
          ? assetDetails.assetType.name
          : 'Unknown',
      },
      {
        key: 'Color',
        value: isDefined(assetDetails.color)
          ? this.utilityService.toTitleCase(assetDetails.color)
          : 'None',
      },
      {
        key: 'Cost Centre',
        value: isDefined(assetDetails.costCentre)
          ? assetDetails.costCentre.name
          : 'None',
      },
      {
        key: 'Groups',
        value: !isEmpty(assetDetails.groups)
          ? assetDetails.groups.map((group) => group.name).join(', ')
          : '',
      },
      {
        key: 'Asset Tag',
        value: assetDetails.assetTag ?? 'None',
      },
      {
        key: 'Icon Name',
        value: assetDetails.mapIconName ?? 'Default',
      },
    ];
  });
  assetTagsSearchResults = signal<AssetTagListItem[] | undefined>(undefined);
  private readonly searchSubject = new Subject<string>();

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    // React to entity changes
    effect(() => {
      const entity = this.entity();
      if (entity && !this.createMode()) {
        this.updateFormFields();
      }
    });
  }

  ngOnInit() {
    this.setUpAssetTagsSearch();
    this.loadSelectOptions();
  }

  private loadSelectOptions() {
    const asset = this.entity();
    const ownerIdValue = this.ownerId();

    const effectiveOwnerId = asset?.owner?.id ?? ownerIdValue;

    if (isNullOrUndefined(effectiveOwnerId)) {
      this.selectOptions = {};
      this.selectOptionsLoaded.set(true);
      this.updateFormFields();
      return;
    }

    Promise.all([
      this.assetGroupingService.getAssetTypes(effectiveOwnerId),
      firstValueFrom(this.entitiesService.listCostCentres(effectiveOwnerId)),
      this.assetGroupingService.getAssetGroupsAsTree(effectiveOwnerId),
    ])
      .then(([assetTypes, costCentres, assetGroups]) => {
        this.selectOptions = {
          assetTypes: assetTypes
            .map((item) => ({
              label: item.name ?? '',
              value: item.id,
            }))
            .sort((a, b) => a.label.localeCompare(b.label)),
          costCentres: costCentres.items
            .map((costCentre) => ({
              label: costCentre.name ?? '',
              value: costCentre.id,
            }))
            .sort((a, b) => a.label.localeCompare(b.label)),
          groups: assetGroups,
        };

        this.selectOptionsLoaded.set(true);
        this.updateFormFields();
      })
      .catch(() => {
        this.selectOptionsLoaded.set(false);
      });
  }

  private setUpAssetTagsSearch(): void {
    this.searchSubject
      .pipe(
        debounceTime(SEARCH_DEBOUNCE_TIME),
        distinctUntilChanged(),
        takeUntilDestroyed(this.destroyRef),
        switchMap((searchTerm) => {
          const owner = this.entity()?.owner;

          if (isNullOrUndefined(owner?.id)) {
            return of({ items: [] });
          }

          const filters = {
            state: 'active',
            name: `*${searchTerm}*`,
          };
          const rqlFilter = this.utilityService.constructRqlFilter(filters);

          return this.entitiesService
            .listAssetTags(owner.id, 0, 10, 'name', rqlFilter)
            .pipe(
              catchError(() => {
                return of({ items: [] });
              }),
            );
        }),
      )
      .subscribe({
        next: (data) => {
          if (isDefined(data) && hasProperty(data, 'items')) {
            this.assetTagsSearchResults.set(
              isNullOrUndefined(data.items) ? [] : data.items,
            );
          }
        },
        error: (error) => {
          console.error('Error searching asset tags:', error);
          this.assetTagsSearchResults.set([]);
        },
      });
  }

  protected override updateFormFields(): void {
    const asset = this.entity();
    this.formFields = [
      createTextField('name', 'Name', asset?.name, {
        name: 'name',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'Name is required',
          },
        ],
      }),
      createDropdownField(
        'mapIconName',
        'Icon Name',
        [
          { label: 'Default', value: 'Default' },
          { label: 'Airplane', value: 'Airplane' },
          { label: 'Ambulance (small)', value: 'Ambulance (small)' },
          { label: 'Ambulance', value: 'Ambulance' },
          { label: 'Boat', value: 'Boat' },
          { label: 'Bus', value: 'Bus' },
          { label: 'Car', value: 'Car' },
          { label: 'Cement Mixer', value: 'Cement Mixer' },
          { label: 'Container', value: 'Container' },
          { label: 'Dump Truck', value: 'Dump Truck' },
          { label: 'Excavator', value: 'Excavator' },
          { label: 'Haul Truck', value: 'Haul Truck' },
          { label: 'Lawn Mower', value: 'Lawn Mower' },
          { label: 'Man', value: 'Man' },
          { label: 'Motorcycle', value: 'Motorcycle' },
          { label: 'Parcel', value: 'Parcel' },
          { label: 'Pickup Truck', value: 'Pickup Truck' },
          { label: 'School Bus (small)', value: 'School Bus (small)' },
          { label: 'School Bus', value: 'School Bus' },
          { label: 'Tractor', value: 'Tractor' },
          { label: 'Trailer', value: 'Trailer' },
          { label: 'Truck (small)', value: 'Truck (small)' },
          { label: 'Truck', value: 'Truck' },
          { label: 'Van (small)', value: 'Van (small)' },
          { label: 'Van', value: 'Van' },
        ],
        asset?.mapIconName ?? 'Default',
        {
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: 'Icon name is required',
            },
          ],
          props: {
            appendTo: 'body',
          },
        },
      ),
      createAutocompleteField('tags', 'Tags', [], [], () => {}, {
        layout: 'horizontal',
        labelWidth: '1/3',
        name: 'tags',
        placeholder: 'Enter tags ...',
        props: {
          appendTo: 'body',
          typeahead: false,
          multiple: true,
          dropdown: false,
        },
      }),
      createDropdownField(
        'assetType',
        'Type',
        (this.selectOptions?.['assetTypes'] as {
          label: string;
          value: string;
        }[]) ?? [],
        asset?.assetType?.id,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'assetType',
          props: {
            appendTo: 'body',
          },
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: 'Asset type is required',
            },
          ],
        },
      ),
      createDropdownField('color', 'Color', this.colors, asset?.color, {
        layout: 'horizontal',
        labelWidth: '1/3',
        name: 'color',
        props: {
          appendTo: 'body',
        },
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'Color is required',
          },
        ],
      }),
      createDropdownField(
        'costCentre',
        'Cost Centre',
        (this.selectOptions?.['costCentres'] as {
          label: string;
          value: string;
        }[]) ?? [],
        asset?.costCentre?.id,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'costCentre',
          props: {
            appendTo: 'body',
          },
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: 'Cost centre is required',
            },
          ],
        },
      ),
      createTreeSelectField(
        'groups',
        'Groups',
        (asset?.groups ?? []).map((group) => ({
          id: group.id,
          label: group.name,
          data: group,
        })),
        this.selectOptions?.['groups'] ?? [],
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'groups',
          props: {
            appendTo: 'body',
            placeholder: 'Select Group',
            multiple: true,
            showClear: true,
            selectionMode: 'checkbox',
            filter: true,
          },
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: 'At least one group is required',
            },
          ],
        },
      ),
      createAutocompleteField(
        'assetTag',
        'Asset Tag',
        typeof asset?.assetTag === 'string' ? asset.assetTag : undefined,
        () => this.assetTagsSearchResults() ?? [],
        this.searchAssetTag.bind(this),
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'assetTag',
          props: {
            appendTo: 'body',
            showClear: true,
            multiple: false,
            field: 'name',
            completeOnFocus: false,
            typeahead: true,
            showEmptyMessage: true,
            emptyMessage: 'No asset tags found',
          },
        },
      ),
    ];
  }

  protected override submitChanges(
    formData: Record<string, string | number>,
  ): void {
    const asset = this.entity();
    if (isNullOrUndefined(asset)) return;
    this.entitiesService
      .updateAsset(asset.id, formData)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: () => {
          this.isFormEditable.set(false);
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'asset',
            entityId: asset.id,
          });
        },
        error: () => {
          this.isFormEditable.set(true);
        },
      });
  }

  protected override onFormValueChange(
    formData: Record<string, string | number | object | null | undefined>,
  ): void {
    const transformedData = { ...formData };

    // Transform assetType ID to IdName object
    if (
      isDefined(transformedData['assetType']) &&
      typeof transformedData['assetType'] === 'string'
    ) {
      const assetTypeOption = this.selectOptions?.['assetTypes']?.find(
        (option) => option.value === transformedData['assetType'],
      );

      if (assetTypeOption) {
        transformedData['assetType'] = {
          id: assetTypeOption.value,
          name: assetTypeOption.label,
        };
      }
    }

    // Transform costCentre ID to IdName object
    if (
      isDefined(transformedData['costCentre']) &&
      typeof transformedData['costCentre'] === 'string'
    ) {
      const costCentreOption = this.selectOptions?.['costCentres']?.find(
        (option) => option.value === transformedData['costCentre'],
      );

      if (costCentreOption) {
        transformedData['costCentre'] = {
          id: costCentreOption.value,
          name: costCentreOption.label,
        };
      }
    }

    // Transform groups array of IDs to array of IdName objects
    if (Array.isArray(transformedData['groups'])) {
      transformedData['groups'] = transformedData['groups'].map((group) => {
        const groupOption: AssetGroupingTreeItem | undefined =
          this.selectOptions?.['groups']?.find(
            (option) => (option as AssetGroupingTreeItem).id === group.id,
          ) as AssetGroupingTreeItem | undefined;

        return groupOption
          ? {
              id: groupOption.id,
              name: groupOption.label,
            }
          : { id: group.id, name: '' };
      });
    }

    if (transformedData['assetTag'] === '') {
      transformedData['assetTag'] = null;
    }
    // Emit the transformed values
    this.formValueChange.emit(transformedData);
  }

  searchAssetTag(searchTerm: string) {
    this.assetTagsSearchResults.set(undefined);
    this.searchSubject.next(searchTerm);
  }
}
