import { Injectable, inject } from '@angular/core';
import { Observable, of } from 'rxjs';

import { isNullOrUndefined } from '../../../../shared/utils';
import { AlertListItem, AlertResponse, EntitiesService } from '../../../../api';
import {
  DataGridParams,
  GridDataService,
  GridResponse,
} from '../../../../shared/models';

@Injectable({
  providedIn: 'root',
})
export class AlertsDataAdapter implements GridDataService<AlertListItem> {
  private readonly entitiesService = inject(EntitiesService);

  getList(params: DataGridParams): Observable<GridResponse<AlertListItem>> {
    const { owner, limit, offset, sortField, filters } = params;

    if (isNullOrUndefined(owner)) {
      return of({ items: [], count: 0 });
    }

    return this.entitiesService.listAlerts(
      owner,
      offset,
      limit,
      sortField as string,
      filters,
    );
  }

  getById(id: string): Observable<AlertResponse> {
    return this.entitiesService.getAlert(id);
  }
}
