import {
  Component,
  computed,
  effect,
  inject,
  OnInit,
  signal,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { ReactiveFormsModule } from '@angular/forms';

import { ButtonModule } from 'primeng/button';

import { AssetListItem, EntitiesService } from '../../../../../api';
import {
  AssetGroupingItem,
  createDropdownField,
} from '../../../../../shared/models';
import {
  isDefined,
  isEmpty,
  isNullOrUndefined,
  isString,
} from '../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../base';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import { AssetGroupingService } from '../../../../../shared/services/asset-grouping.service';
import { DEFAULT_SYSTEM_ID } from '../../../../../core/models';

@Component({
  selector: 'app-asset-categories-section',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    ButtonModule,
    GridComponent,
    DynamicFormComponent,
  ],
  templateUrl: './asset-categories-section.component.html',
  styleUrl: './asset-categories-section.component.scss',
})
export class AssetCategoriesSectionComponent
  extends EntitySectionBaseComponent<AssetListItem>
  implements OnInit
{
  private readonly entitiesService = inject(EntitiesService);
  private readonly assetGroupingService = inject(AssetGroupingService);
  protected readonly selectOptionsLoaded = signal<boolean>(false);
  selectOptions: Record<string, { label: string; value: string }[]> = {};

  readonly assetDetails = computed(() => {
    const assetDetails = this.entity();
    if (!isDefined(assetDetails)) return [];

    return [
      {
        key: 'Department',
        value: isEmpty(assetDetails.categories)
          ? 'None'
          : assetDetails.categories
              .filter((category) => isDefined(category))
              .map((category) => category?.name)
              .join(', '),
      },
    ];
  });
  assetCategories: AssetGroupingItem[] = [];

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    // React to entity changes
    effect(() => {
      const assetDetails = this.entity();
      if (assetDetails && this.selectOptionsLoaded()) {
        this.updateFormFields();
      }
    });
  }

  ngOnInit() {
    this.loadSelectOptions();
  }

  private loadSelectOptions() {
    const asset = this.entity();
    if (!isDefined(asset) || !isString(asset.id)) {
      this.selectOptions = {};
      this.selectOptionsLoaded.set(true);
      return;
    }

    this.assetGroupingService
      .getAssetCategories(asset.owner.id)
      .then((assetCategories) => {
        this.assetCategories = assetCategories;
        this.selectOptions = {
          assetCategories: assetCategories
            .map((item) => ({
              label: item.name ?? '',
              value: item.id,
            }))
            .sort((a, b) => a.label.localeCompare(b.label)),
        };

        this.selectOptionsLoaded.set(true);
      })
      .catch(() => {
        this.selectOptions = {};
      });
  }

  protected override updateFormFields(): void {
    this.formFields = [];
    this.assetCategories
      .filter((category) => category?.parent === DEFAULT_SYSTEM_ID)
      .forEach((category) => {
        this.formFields.push(
          createDropdownField(
            `category${category.id}`,
            category.name,
            this.selectOptions?.['assetCategories'] ?? [],
            category.id,
            {
              layout: 'horizontal',
              labelWidth: '1/3',
              name: `category${category.id}`,
              props: {
                appendTo: 'body',
              },
            },
          ),
        );
      });
  }

  protected override submitChanges(
    formData: Record<string, string | number>,
  ): void {
    const asset = this.entity();
    if (isNullOrUndefined(asset)) return;
    this.entitiesService
      .updateAsset(asset.id, this.transformFormData(formData))
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: () => {
          this.isFormEditable.set(false);
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'asset',
            entityId: asset.id,
          });
        },
        error: () => {
          this.isFormEditable.set(true);
        },
      });
  }

  protected override onFormValueChange(
    formData: Record<string, unknown>,
  ): void {
    const transformedData = this.transformFormData(formData);

    // Emit the transformed values
    this.formValueChange.emit(transformedData);
  }

  override transformFormData(formData: Record<string, unknown>) {
    const transformedData = {
      categories: [] as { id: string; name: string }[],
    };

    Object.values({ ...formData }).forEach((value) => {
      if (isDefined(value) && isString(value)) {
        const categoryId = value;
        const category = this.assetCategories.find(
          (cat) => cat.id === categoryId,
        );
        if (category) {
          transformedData.categories.push({
            id: category.id,
            name: category.name,
          });
        }
      }
    });

    return transformedData;
  }
}
