import { Injectable, inject } from '@angular/core';
import { Observable, of } from 'rxjs';

import { isNullOrUndefined } from '../../../../shared/utils';
import { UserListItem, UserResponse, AccountsService } from '../../../../api';
import {
  DataGridParams,
  EntityDataAdapter,
  GridResponse,
} from '../../../../shared/models';

@Injectable({
  providedIn: 'root',
})
export class UsersDataAdapter
  implements EntityDataAdapter<UserListItem, UserResponse>
{
  private readonly accountsService = inject(AccountsService);

  getList(params: DataGridParams): Observable<GridResponse<UserListItem>> {
    const { owner, limit, offset, sortField, filters } = params;

    if (isNullOrUndefined(owner)) {
      return of({ items: [], count: 0 });
    }

    return this.accountsService.listUsers(
      owner,
      offset,
      limit,
      sortField as string,
      filters,
    );
  }

  getById(id: string): Observable<UserResponse> {
    return this.accountsService.getUser(id);
  }
}
