import { CommonModule } from '@angular/common';
import {
  Component,
  computed,
  effect,
  inject,
  OnInit,
  signal,
} from '@angular/core';
import { ReactiveFormsModule } from '@angular/forms';
import { ButtonModule } from 'primeng/button';
import { InputTextModule } from 'primeng/inputtext';
import { ChipModule } from 'primeng/chip';

import { EntitySectionBaseComponent } from '../../../components/base/entity-section-base';
import { AssetResponse, EntitiesService } from '../../../../../api';
import {
  isDefined,
  isNullOrUndefined,
  isString,
} from '../../../../../shared/utils';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import {
  createDropdownField,
  createNumberField,
  MeasurementUnitType,
} from '../../../../../shared/models';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { MeasurementUnitsService } from '../../../../../shared/services/measurement-units/measurement-units.service';

@Component({
  selector: 'app-asset-event-triggers-section',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    ButtonModule,
    InputTextModule,
    ChipModule,
    GridComponent,
    DynamicFormComponent,
  ],
  templateUrl: './asset-event-triggers-section.component.html',
  styleUrl: './asset-event-triggers-section.component.scss',
})
export class AssetEventTriggersSectionComponent
  extends EntitySectionBaseComponent<AssetResponse>
  implements OnInit
{
  private readonly entitiesService = inject(EntitiesService);
  private readonly measurementUnitsService = inject(MeasurementUnitsService);
  protected readonly selectOptionsLoaded = signal<boolean>(false);
  selectOptions: Record<string, { label: string; value: string }[]> = {};
  readonly assetEventTriggers = computed(() => {
    const asset = this.entity();
    const assetEventTriggers = asset?.parameters;
    if (isNullOrUndefined(assetEventTriggers)) return [];

    return [
      {
        key: 'Max Speed',
        value: isDefined(assetEventTriggers.overspeed)
          ? this.measurementUnitsService.format(
              assetEventTriggers.overspeed,
              MeasurementUnitType.SPEED,
            ).format
          : 'None',
      },
      {
        key: 'Overspeed Profile',
        value: isDefined(asset?.overspeedProfile)
          ? asset?.overspeedProfile?.name
          : 'None',
      },
      {
        key: 'Speed Tolerance',
        value: isDefined(assetEventTriggers.overspeedTolerance)
          ? `${assetEventTriggers.overspeedTolerance}%`
          : 'None',
      },
      {
        key: 'Excessive Idle',
        value: isDefined(assetEventTriggers.excessiveIdle)
          ? `${assetEventTriggers.excessiveIdle} minutes`
          : 'None',
      },
      {
        key: 'Max Trip Distance',
        value: isDefined(assetEventTriggers.maxTripDistance)
          ? `${
              this.measurementUnitsService.format(
                assetEventTriggers.maxTripDistance,
                MeasurementUnitType.DISTANCE,
              ).value
            } ${this.measurementUnitsService.unit(
              MeasurementUnitType.DISTANCE,
            )}`
          : 'None',
      },
      {
        key: 'Max Trip Time',
        value: isDefined(assetEventTriggers.maxTripTime)
          ? `${assetEventTriggers.maxTripTime} minutes`
          : 'None',
      },
      {
        key: 'Max inactive time',
        value: isDefined(assetEventTriggers.maxInactiveTime)
          ? `${assetEventTriggers.maxInactiveTime} minutes`
          : 'None',
      },
    ];
  });

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    // React to entity changes
    effect(() => {
      const assetEventTriggers = this.entity();
      if (assetEventTriggers && this.selectOptionsLoaded()) {
        this.updateFormFields();
      }
    });
  }

  ngOnInit() {
    this.loadSelectOptions();
  }

  private loadSelectOptions() {
    const asset = this.entity();
    if (!isDefined(asset) || !isString(asset.id)) {
      this.selectOptions = {};
      this.selectOptionsLoaded.set(true);
      this.updateFormFields();
      return;
    }

    this.entitiesService
      .listOverspeedProfiles(asset.owner.id)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe((response) => {
        this.selectOptions = {
          overspeedProfiles: response.items
            .map((item) => ({
              label: item.name ?? '',
              value: item.id,
            }))
            .sort((a, b) => a.label.localeCompare(b.label)),
        };

        this.selectOptionsLoaded.set(true);
      });
  }

  protected override updateFormFields(): void {
    const asset = this.entity();
    this.formFields = [
      createNumberField(
        'overspeed',
        'Max Speed',
        asset?.parameters?.overspeed ?? undefined,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'overspeed',
          props: {
            suffix: this.measurementUnitsService.unitSymbol(
              MeasurementUnitType.SPEED,
            ),
          },
        },
      ),
      createDropdownField(
        'overspeedProfile',
        'Overspeed Profile',
        this.selectOptions['overspeedProfiles'],
        asset?.overspeedProfile?.id ?? undefined,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'overspeedProfile',
          props: {
            placeholder: 'Select Overspeed Profile',
            filter: true,
            showClear: true,
            clearButtonAriaLabel: 'Clear selection',
          },
        },
      ),
      createNumberField(
        'overspeedTolerance',
        'Speed Tolerance',
        asset?.parameters?.overspeedTolerance ?? undefined,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'overspeedTolerance',
          props: {
            suffix: '%',
          },
        },
      ),
      createNumberField(
        'excessiveIdle',
        'Excessive Idle',
        asset?.parameters?.excessiveIdle ?? undefined,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'excessiveIdle',
          props: {
            suffix: 'minutes',
          },
        },
      ),
      createNumberField(
        'maxTripDistance',
        'Max Trip Distance',
        asset?.parameters?.maxTripDistance ?? undefined,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'maxTripDistance',
          props: {
            suffix: this.measurementUnitsService.unit(
              MeasurementUnitType.DISTANCE,
            ),
          },
        },
      ),
      createNumberField(
        'maxTripTime',
        'Max Trip Time',
        asset?.parameters?.maxTripTime ?? undefined,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'maxTripTime',
          props: {
            suffix: 'minutes',
          },
        },
      ),
      createNumberField(
        'maxInactiveTime',
        'Max inactive time',
        asset?.parameters?.maxInactiveTime ?? undefined,
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'maxInactiveTime',
          props: {
            suffix: 'minutes',
          },
        },
      ),
    ];
  }

  protected override submitChanges(
    formData: Record<string, string | number>,
  ): void {
    const asset = this.entity();
    if (isNullOrUndefined(asset)) return;
    this.handleEntityUpdate(
      this.entitiesService
        .updateAsset(asset.id, { parameters: formData })
        .pipe(takeUntilDestroyed(this.destroyRef)),
      'Asset Event triggers updated successfully',
    );
  }
}
