import { Injectable } from '@angular/core';

import { ClientResponse } from '../../../api';
import { AdminDetailSection } from '../models';
import { SectionConfigBuilder } from './section-config.factory';
import { FeatureSectionComponent } from '../components/shared/feature-section/feature-section.component';
import { AppFeatures } from '../../../core/models';

@Injectable({ providedIn: 'root' })
export class ClientSectionConfigFactory {
  /**
   * Create all client sections in one call
   * @param client The client object to display in the sections
   * @returns An array of AdminDetailSection objects representing all client sections
   */
  createAllClientSections(
    client: ClientResponse | null,
    appFeatures: string[],
  ): AdminDetailSection[] {
    const features = appFeatures
      .map((feature) =>
        SectionConfigBuilder.forClient(client)
          .addSection(
            feature,
            'Features',
            FeatureSectionComponent<ClientResponse>,
            {
              category: 'features',
            },
            {
              feature: AppFeatures[feature],
            },
          )
          .build(),
      )
      .flat();
    return [
      ...SectionConfigBuilder.createClientInformationSections(client),
      ...SectionConfigBuilder.createClientSettingsSections(client),
      ...features,
      ...SectionConfigBuilder.createClientChangesSections(client),
    ];
  }
}
