import { CommonModule } from '@angular/common';
import {
  Component,
  computed,
  effect,
  inject,
  OnInit,
  signal,
} from '@angular/core';
import { ReactiveFormsModule, Validators } from '@angular/forms';
import { ConfirmationService, MessageService } from 'primeng/api';

import { ButtonModule } from 'primeng/button';
import { DataViewModule } from 'primeng/dataview';
import { DividerModule } from 'primeng/divider';
import { InputTextModule } from 'primeng/inputtext';
import { PanelModule } from 'primeng/panel';
import { ToastModule } from 'primeng/toast';
import { ConfirmDialog } from 'primeng/confirmdialog';

import { DynamicFormModalComponent } from '../../../../../shared/components/forms/dynamic-form-modal/dynamic-form-modal.component';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import {
  AccountsService,
  AssetResponse,
  EntitiesService,
  IdName,
} from '../../../../../api';
import { UtilityService } from '../../../../../core/services/utility.service';
import { FormAction, createTextField } from '../../../../../shared/models';
import { isEmpty, isNullOrUndefined } from '../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../base';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import {
  catchError,
  debounceTime,
  distinctUntilChanged,
  EMPTY,
  Subject,
  switchMap,
} from 'rxjs';

@Component({
  selector: 'app-asset-sharing-section',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    ButtonModule,
    InputTextModule,
    DynamicFormModalComponent,
    DataViewModule,
    PanelModule,
    DividerModule,
    GridComponent,
    ToastModule,
    ConfirmDialog,
  ],
  providers: [MessageService, ConfirmationService],
  templateUrl: './asset-sharing-section.component.html',
  styleUrl: './asset-sharing-section.component.scss',
})
export class AssetSharingSectionComponent
  extends EntitySectionBaseComponent<AssetResponse>
  implements OnInit
{
  private readonly entitiesService = inject(EntitiesService);
  readonly utilityService = inject(UtilityService);
  readonly accountsService = inject(AccountsService);
  readonly confirmationService = inject(ConfirmationService);

  // UI state signals
  readonly showModal = signal<boolean>(false);

  // Data signals
  readonly selectedClient = signal<IdName | null>(null);
  private readonly searchClientSubject = new Subject<string>();

  readonly assetSharedWith = computed(() => {
    const assetSharedWith = this.entity()?.sharedWith;
    if (isNullOrUndefined(assetSharedWith)) return [];

    return [
      {
        key: 'Shared With',
        value: assetSharedWith
          .map((sharedWith: IdName) => sharedWith.name)
          .join(', '),
      },
    ];
  });

  override readonly actions: FormAction[] = [
    {
      label: 'Cancel',
      action: () => {
        this.onClose();
      },
      severity: 'secondary',
    },
    {
      label: 'Add Client',
      action: () => {
        const selectedClientValue = this.selectedClient();
        if (selectedClientValue) {
          this.addClientToSharedList(selectedClientValue);
        }
      },
      severity: 'primary',
      // Only enable when a client is found
      disabled: () => this.selectedClient() === null,
    },
  ];

  sharedWith: IdName[] = [];

  constructor() {
    super();

    this.columns = [
      {
        field: 'key',
        header: '',
        transform: 'uppercase',
      },
      { field: 'value', header: '' },
    ];

    // React to entity changes
    effect(() => {
      const assetSharedWith = this.entity()?.sharedWith;
      if (assetSharedWith) {
        this.sharedWith = assetSharedWith;
        this.updateFormFields();
      }
    });
  }

  ngOnInit(): void {
    this.setupSearchClient();
  }

  private setupSearchClient() {
    this.searchClientSubject
      .pipe(
        debounceTime(300),
        distinctUntilChanged(),
        takeUntilDestroyed(this.destroyRef),
        switchMap((searchTerm) => {
          if (isNullOrUndefined(searchTerm)) {
            return EMPTY;
          }
          this.isLoading.set(true);
          return this.accountsService.getClientByPin(searchTerm).pipe(
            catchError(() => {
              this.selectedClient.set(null);
              this.isLoading.set(false);
              return EMPTY;
            }),
          );
        }),
      )
      .subscribe({
        next: (response) => {
          this.isLoading.set(false);
          if (!isEmpty(response)) {
            this.selectedClient.set(response);
          } else {
            this.selectedClient.set(null);
          }
        },
        error: () => {
          this.isLoading.set(false);
          this.selectedClient.set(null);
        },
      });
  }

  private searchClient(searchTerm: string) {
    if (isNullOrUndefined(searchTerm)) {
      this.selectedClient.set(null);
      return;
    }

    this.searchClientSubject.next(searchTerm);
  }

  protected override updateFormFields(): void {
    this.formFields = [
      createTextField('pin', 'PIN', '', {
        name: 'pin',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'PIN is required',
          },
          {
            name: 'minlength',
            validator: Validators.minLength(3),
            message: 'PIN must be at least 3 characters',
          },
        ],
        events: {
          onChange: (value: string) => {
            // Your handler logic here
            if (value && value.length >= 3) {
              this.searchClient(value);
            } else {
              this.selectedClient.set(null);
            }
          },
        },
      }),
    ];
  }

  /**
   * Open modal to add shared entity
   */
  openAddEntityModal(): void {
    this.selectedClient.set(null);
    this.updateFormFields();
    this.showModal.set(true);
  }

  /**
   * Add client to shared entities list
   */
  private addClientToSharedList(client: IdName): void {
    // Check if client is already in shared list
    const isDuplicate = this.sharedWith.some((item) => item.id === client.id);

    if (isDuplicate) {
      this.messageService.add({
        severity: 'warn',
        summary: 'Already Shared',
        detail: `Asset is already shared with ${client.name}`,
      });
      return;
    }

    // Add to shared list
    this.sharedWith = [...this.sharedWith, client];
    // Reset form and close modal
    this.onClose();
  }

  protected override submitChanges(
    _formData: Record<string, string | number>,
  ): void {
    const asset = this.entity();
    if (!asset) return;

    // Update asset with new shared list
    this.entitiesService
      .updateAsset(asset.id, {
        sharedWith: this.sharedWith,
      })
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        catchError((error) => {
          this.isLoading.set(false);
          this.messageService.add({
            severity: 'error',
            summary: 'Error',
            detail: 'Failed to update sharing settings',
          });
          console.error('Failed to update shared entities', error);
          return EMPTY;
        }),
      )
      .subscribe({
        next: (updatedAsset) => {
          this.isLoading.set(false);
          // Update local list
          this.sharedWith = updatedAsset.sharedWith || [];
        },
      });
  }

  onClose() {
    this.showModal.set(false);
    this.selectedClient.set(null);
  }

  removeClientFromSharedList(client: IdName): void {
    this.confirmationService.confirm({
      message: `Are you sure you want to remove sharing with ${client.name}?`,
      accept: () => {
        this.sharedWith = this.sharedWith.filter(
          (item) => item.id !== client.id,
        );
      },
    });
  }
}
