import { Injectable } from '@angular/core';

import { VendorResponse } from '../../../api';
import { AdminDetailSection } from '../models';
import { SectionConfigBuilder } from './section-config.factory';
import { FeedSectionComponent } from '../components/shared/feed-section/feed-section.component';

@Injectable({ providedIn: 'root' })
export class VendorSectionConfigFactory {
  /**
   * Create all vendor sections in one call
   * @param vendor The vendor object to display in the sections
   * @returns An array of AdminDetailSection objects representing all vendor sections
   */
  createAllVendorSections(vendor: VendorResponse | null): AdminDetailSection[] {
    return [
      ...SectionConfigBuilder.createVendorInformationSections(vendor),
      ...SectionConfigBuilder.createVendorSettingsSections(vendor),
      ...[
        {
          id: 'vendor-changes',
          title: 'Changes',
          component: FeedSectionComponent,
          componentInputs: {
            entity: vendor,
            entityType: 'vendor',
          },
          category: 'feed' as const,
          order: 10,
        },
      ],
    ];
  }
}
