import {
  Component,
  computed,
  inject,
  signal,
  OnInit,
  input,
  OnDestroy,
  ChangeDetectorRef,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import {
  Observable,
  Subject,
  debounceTime,
  distinctUntilChanged,
  firstValueFrom,
  switchMap,
} from 'rxjs';

// PrimeNG imports
import { ButtonModule } from 'primeng/button';
import { MessageModule } from 'primeng/message';

// FontAwesome
import { FontAwesomeModule } from '@fortawesome/angular-fontawesome';
import { faClipboardList } from '@fortawesome/free-solid-svg-icons';

// API imports
import {
  AccountsService,
  UserListItem,
  UserCreateRequest,
  UserResponse,
  UserPermissions,
  UserClientPermissions,
  ClientListItem,
  ClientsService,
} from '../../../../../api';

// Shared imports
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import {
  hasProperty,
  isDefined,
  isEmpty,
  isNullOrUndefined,
} from '../../../../../shared/utils';

// Component imports
import { EntitySectionBaseComponent } from '../../base';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { RequestCacheService } from '../../../../../shared/services/request-cache.service';
import {
  createAssetFilterField,
  createAutocompleteField,
  createModalListField,
  FormFieldConfig,
  ListFieldModalConfig,
} from '../../../../../shared/models';
import { ModalListFormComponent } from '../../../../../shared/components/forms/modal-list-form/modal-list-form.component';
import { Validators } from '@angular/forms';
import {
  SEARCH_DEBOUNCE_TIME,
  CLIENT_SEARCH_LIMIT,
} from '../../../../users/profile/profile.component';
import { AuthDataService } from '../../../../../core/services/auth-data.service';
import { UtilityService } from '../../../../../core/services/utility.service';

@Component({
  selector: 'app-user-client-permissions-section',
  imports: [
    CommonModule,
    ButtonModule,
    GridComponent,
    MessageModule,
    FontAwesomeModule,
    DynamicFormComponent,
  ],
  templateUrl: './user-client-permissions-section.component.html',
  styleUrl: './user-client-permissions-section.component.scss',
})
export class UserClientPermissionsSectionComponent
  extends EntitySectionBaseComponent<UserListItem | UserCreateRequest>
  implements OnInit, OnDestroy
{
  readonly ownerId = input<string | null>(null);
  private readonly accountsService = inject(AccountsService);
  private readonly requestCache = inject(RequestCacheService);
  private readonly utilityService = inject(UtilityService);
  private readonly clientsService = inject(ClientsService);
  private readonly authDataService = inject(AuthDataService);

  private readonly cdr = inject(ChangeDetectorRef);
  faClipboardList = faClipboardList;
  private readonly clientNames = signal<Record<string, string>>({});
  private clientCacheKeys: string[] = [];
  readonly userClientPermissions = computed(() => {
    const user = this.entity();
    const permissions = (user as unknown as UserResponse)?.permissions?.clients;
    const names = this.clientNames();

    if (!isDefined(permissions)) {
      return [];
    }

    const clientIds = Object.keys(permissions);

    if (clientIds.length === 0) {
      return [
        {
          key: 'Clients',
          value: 'No Clients',
        },
      ];
    }

    if (isEmpty(names)) {
      return [
        {
          key: 'Clients',
          value: 'Loading client names...',
        },
      ];
    }

    // Map client IDs to names, fallback to ID if name not loaded yet
    const clientNames = clientIds.map((id) => names[id] || id).join(', ');

    return [
      {
        key: 'Clients',
        value: clientNames,
      },
    ];
  });
  clientPermissionsModalConfig:
    | ListFieldModalConfig<{ clientId: string } & UserClientPermissions>
    | undefined;
  clientSearchResults = signal<ClientListItem[] | undefined>([]);
  private readonly searchSubject = new Subject<string>();

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];
  }

  ngOnInit() {
    void this.loadClientPermissions();
    this.setupClientSearch();
  }

  ngOnDestroy() {
    // Clear all client cache entries created by this component
    this.clientCacheKeys.forEach((key) => {
      this.requestCache.clearCache(key);
    });
    this.clientCacheKeys = [];
  }

  protected override updateFormFields(): void {
    const userPermissions: Record<string, UserClientPermissions> =
      this.entity()?.permissions?.clients ?? {};
    const permissionsArray = Object.entries(userPermissions).map(
      ([clientId, permissions]) => ({
        clientId,
        ...permissions,
      }),
    );

    this.clientPermissionsModalConfig = {
      modalComponent: ModalListFormComponent,
      modalTitle: 'Client Permissions',
      listItemFormatter: (
        item: { clientId: string } & UserClientPermissions,
      ) => {
        const clientName = this.clientNames()[item.clientId] || item.clientId;
        return {
          id: item.clientId,
          display: `${clientName}`,
          icon: 'pi pi-building',
        };
      },
      modalFields: (): FormFieldConfig[] => {
        return [
          createAutocompleteField(
            'client',
            'Client',
            '',
            () => this.clientSearchResults() || [],
            this.searchClient.bind(this),
            {
              name: 'client',
              props: {
                forceSelection: true,
                field: 'name',
                placeholder: 'Search for clients...',
                completeOnFocus: true,
                typeahead: true,
                showEmptyMessage: true,
                appendTo: 'body',
              },
              hint: 'Enter a client name.',
            },
          ),
          createAssetFilterField(
            'filter',
            'Asset Filter',
            undefined,
            ['groups'],
            {
              name: 'filter',
              required: true,
              validations: [
                {
                  name: 'required',
                  validator: Validators.required,
                  message: 'Asset filter is required',
                },
              ],
              props: {
                multiSelect: true,
                showGroupTabs: true,
              },
            },
          ),
        ];
      },
    };

    this.formFields = [
      createModalListField('permissions', 'Clients', permissionsArray, {
        name: 'permissions',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'Client permissions are required',
          },
        ],
        props: {
          modalConfig: this
            .clientPermissionsModalConfig as unknown as ListFieldModalConfig<unknown>,
        },
      }),
    ];
  }

  protected override submitChanges(formData: Record<string, unknown>): void {
    const user = this.entity();
    if (isNullOrUndefined(user)) return;

    this.accountsService
      .updateUser(user.id, {
        permissions: formData['permissions'] as UserPermissions,
      })
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response) => {
          this.isFormEditable.set(false);
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'user',
            operation: 'update',
            entityId: user.id,
            data: response,
          });
          void this.loadClientPermissions(); // Refresh the list
        },
        error: () => {
          this.isFormEditable.set(true);
        },
      });
  }

  override getUpdateMethod(): (
    id: string,
    data: Partial<UserResponse | UserCreateRequest>,
  ) => Observable<UserResponse> {
    return (id, data) => this.accountsService.updateUser(id, data);
  }

  async loadClientPermissions(): Promise<void> {
    const user = this.entity();
    const permissions = (user as unknown as UserResponse)?.permissions?.clients;

    if (!isDefined(permissions)) {
      return;
    }

    const clientIds = Object.keys(permissions);
    const namePromises = clientIds.map(async (clientId) => {
      const name = await this.loadClientName(clientId);
      return { id: clientId, name };
    });

    try {
      const clientNamesArray = await Promise.all(namePromises);
      const namesRecord: Record<string, string> = {};

      clientNamesArray.forEach(({ id, name }) => {
        namesRecord[id] = name;
      });

      this.clientNames.set(namesRecord);
    } catch (error) {
      console.error('Error loading client names:', error);
    }
  }

  async loadClientName(clientId: string): Promise<string> {
    if (!clientId) return Promise.resolve('Unknown Client');

    const cacheKey = `client-name/${clientId}`;

    // Track this cache key for cleanup
    if (!this.clientCacheKeys.includes(cacheKey)) {
      this.clientCacheKeys.push(cacheKey);
    }

    try {
      const client = await this.requestCache.getOrFetchAsync(cacheKey, () =>
        firstValueFrom(this.accountsService.getClient(clientId)),
      );
      return client.name ?? clientId;
    } catch {
      return 'Unknown Client';
    }
  }

  private setupClientSearch(): void {
    this.searchSubject
      .pipe(
        debounceTime(SEARCH_DEBOUNCE_TIME),
        distinctUntilChanged(),
        takeUntilDestroyed(this.destroyRef),
        switchMap((searchTerm) => {
          const owner = this.authDataService.getUserProfile()?.owner;
          if (!isDefined(owner) || !hasProperty(owner, 'id')) {
            throw new Error('Owner ID not found');
          }

          const filters = {
            state: 'active',
            name: `*${searchTerm}*`,
          };
          const rqlFilter = this.utilityService.constructRqlFilter(filters);

          return this.clientsService.listClients(
            owner.id,
            0,
            CLIENT_SEARCH_LIMIT,
            'name',
            rqlFilter,
          );
        }),
      )
      .subscribe({
        next: (data) => {
          if (isDefined(data) && hasProperty(data, 'items')) {
            this.clientSearchResults.set(
              isNullOrUndefined(data.items) ? [] : data.items,
            );
            this.cdr.detectChanges();
          }
        },
        error: (error) => {
          console.error('Error searching clients:', error);
          this.clientSearchResults.set([]);
        },
      });
  }

  searchClient(searchTerm: string) {
    if (!searchTerm || searchTerm.trim() === '' || searchTerm.length < 3) {
      this.clientSearchResults.set([]);
    } else {
      this.searchSubject.next(searchTerm.trim());
    }
  }
}
