import { CommonModule } from '@angular/common';
import {
  Component,
  computed,
  effect,
  inject,
  input,
  signal,
} from '@angular/core';

import { ButtonModule } from 'primeng/button';
import { InputTextModule } from 'primeng/inputtext';
import { Observable } from 'rxjs';

import {
  EntitiesService,
  DeviceTypeResponse,
  DeviceTypeIOCapabilities,
  DeviceCreateRequest,
  DeviceResponse,
} from '../../../../../api';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import {
  createDropdownField,
  createTextField,
  FormAction,
  FormFieldConfig,
} from '../../../../../shared/models';
import { EntityOperationRegistryService } from '../../../services/entity/entity-operation-registry.service';
import { EntitySectionBaseComponent } from '../../base';
import {
  isDefined,
  isEmpty,
  setNestedProperty,
} from '../../../../../shared/utils';
import { DynamicFormModalComponent } from '../../../../../shared/components/forms/dynamic-form-modal/dynamic-form-modal.component';
import { FormGroup } from '@angular/forms';

type DeviceEntity = DeviceResponse | DeviceCreateRequest;

// Define the type parameters for the mixin
@Component({
  selector: 'app-device-parameters-section',
  imports: [
    CommonModule,
    ButtonModule,
    InputTextModule,
    GridComponent,
    DynamicFormComponent,
    DynamicFormModalComponent,
  ],
  templateUrl: './device-parameters-section.component.html',
  styleUrl: './device-parameters-section.component.scss',
})
export class DeviceParametersSectionComponent extends EntitySectionBaseComponent<DeviceEntity> {
  readonly ownerId = input<string | null>(null);
  readonly deviceType = input.required<DeviceTypeResponse | null>();
  readonly entitiesService = inject(EntitiesService);
  private readonly operationRegistry = inject(EntityOperationRegistryService);

  protected readonly customValues = signal<Record<string, string>>({});

  readonly deviceDeviceParameters = computed(() => {
    const deviceDeviceParameters = this.entity()?.parameters;
    if (!isDefined(deviceDeviceParameters)) return [];

    return [
      {
        key: 'Active Input',
        value: isEmpty(deviceDeviceParameters.active_input)
          ? 'None'
          : deviceDeviceParameters.active_input,
      },
      {
        key: 'Hours Input',
        value: isEmpty(deviceDeviceParameters.hours_input)
          ? 'None'
          : deviceDeviceParameters.hours_input,
      },
      {
        key: 'Idling Input',
        value: isEmpty(deviceDeviceParameters.idling_input)
          ? 'None'
          : deviceDeviceParameters.idling_input,
      },
      {
        key: 'Invert Idling Input',
        value:
          (deviceDeviceParameters.idling_input_invert ?? false) ? 'Yes' : 'No',
      },
    ];
  });
  isCustomInputModalOpen = false;
  customInputFormFields: FormFieldConfig[] = [];
  private currentEditField: string | null = null;
  modalActions: FormAction[] = [
    {
      label: 'Cancel',
      action: () => this.onClose(),
      severity: 'secondary',
    },
    {
      label: 'Save',
      action: (formGroup: FormGroup) => {
        this.onSaveCustomInput(formGroup);
      },
      severity: 'primary',
    },
  ];

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    effect(() => {
      const deviceType = this.deviceType();

      if (isDefined(deviceType)) {
        this.updateFormFields();
      }
    });
  }

  private getIOOptions(
    ioCapabilities: DeviceTypeIOCapabilities | undefined,
    currentValue?: string | null,
  ): { label: string; value: string }[] {
    const options: { label: string; value: string }[] = [];

    // Add digital inputs
    if (isDefined(ioCapabilities?.digital_input)) {
      Object.keys(ioCapabilities.digital_input).forEach((key) => {
        let label = key;

        // Special handling for known inputs
        if (key === 'ignition') {
          label = 'Ignition Wire';
        } else if (key === 'movement') {
          label = 'Movement Detection';
        }

        options.push({ label, value: key });
      });
    }

    // Add digital outputs
    if (isDefined(ioCapabilities?.digital_output)) {
      Object.keys(ioCapabilities.digital_output).forEach((key) => {
        options.push({ label: key, value: key });
      });
    }

    // Sort alphabetically
    options.sort((a, b) => a.label.localeCompare(b.label));

    // Add current value if it's custom (not in the list and not empty/none/emulate/speed)
    if (
      isDefined(currentValue) &&
      !options.some((o) => o.value === currentValue) &&
      !['', 'none', 'emulate', 'speed'].includes(currentValue)
    ) {
      options.push({ label: currentValue, value: currentValue });
    }

    // Add custom option
    options.push({ label: 'Custom...', value: '_custom_' });

    return options;
  }

  protected override updateFormFields(): void {
    const device = this.entity();
    const deviceTypeData = this.deviceType();
    const parameters = device?.parameters || {};

    // Get IO options with current active_input value if custom
    const activeInputOptions = this.getIOOptions(
      deviceTypeData?.ioCapabilities,
      parameters.active_input,
    );

    // Get IO options with current hours_input value if custom
    const hoursInputOptions = this.getIOOptions(
      deviceTypeData?.ioCapabilities,
      parameters.hours_input,
    );

    // Get IO options with current idling_input value if custom
    const idlingInputOptions = this.getIOOptions(
      deviceTypeData?.ioCapabilities,
      parameters.idling_input,
    );

    this.formFields = [
      createDropdownField(
        'active_input',
        'Active Input',
        [
          { label: 'None', value: '' },
          { label: 'Emulate', value: 'emulate' },
          ...activeInputOptions,
        ],
        parameters.active_input,
        {
          name: 'active_input',
          props: {
            appendTo: 'body',
          },
          events: {
            onChange: (event) => {
              if (event === '_custom_') {
                this.openCustomInputModal('active_input');
              }
            },
          },
        },
      ),
      createDropdownField(
        'hours_input',
        'Hours Input',
        [
          { label: 'None', value: '' },
          { label: 'Emulate', value: 'emulate' },
          ...hoursInputOptions,
        ],
        parameters.hours_input,
        {
          name: 'hours_input',
          props: {
            appendTo: 'body',
          },
          events: {
            onChange: (event) => {
              if (event === '_custom_') {
                this.openCustomInputModal('hours_input');
              }
            },
          },
        },
      ),
      createDropdownField(
        'idling_input',
        'Idling Input',
        [{ label: 'Speed', value: 'speed' }, ...idlingInputOptions],
        parameters.idling_input,
        {
          name: 'idling_input',
          props: {
            appendTo: 'body',
          },
          events: {
            onChange: (event) => {
              if (event === '_custom_') {
                this.openCustomInputModal('idling_input');
              }
            },
          },
        },
      ),
      createDropdownField(
        'idling_input_invert',
        'Invert Idling Input',
        [
          { label: 'Yes', value: true },
          { label: 'No', value: false },
        ],
        parameters.idling_input_invert,
        {
          name: 'idling_input_invert',
          props: {
            appendTo: 'body',
          },
        },
      ),
    ];
  }

  override getUpdateMethod(): (
    id: string,
    data: Partial<DeviceEntity>,
  ) => Observable<DeviceResponse> {
    return (
      this.operationRegistry.getOperation<
        DeviceEntity,
        DeviceCreateRequest,
        DeviceResponse,
        'update'
      >('device', 'update') ??
      ((id, data) => this.entitiesService.updateDevice(id, data))
    );
  }

  openCustomInputModal(fieldName: string): void {
    this.currentEditField = fieldName;

    // Get current value as default
    const currentValue = this.entity()?.parameters?.[fieldName] ?? '';

    this.customInputFormFields = [
      createTextField('custom_input', 'Input', currentValue, {
        name: 'custom_input',
      }),
    ];
    this.isCustomInputModalOpen = true;
  }

  onClose() {
    this.isCustomInputModalOpen = false;
    this.currentEditField = null;
  }

  onSaveCustomInput(formGroup: FormGroup): void {
    const customValue = formGroup.get('custom_input')?.value;

    if (isDefined(customValue) && isDefined(this.currentEditField)) {
      // Store the custom value for later use
      const customValues = this.customValues();
      this.customValues.set({
        ...customValues,
        [this.currentEditField]: customValue,
      });

      // Find the field in the form fields array
      const fieldIndex = this.formFields.findIndex(
        (field) => field.name === this.currentEditField,
      );

      if (fieldIndex !== -1) {
        const field = this.formFields[fieldIndex];
        const existingOptions = (field.options || []) as unknown as {
          label: string;
          value: string;
        }[];

        // Create a new dropdown field with updated options and selected value
        const updatedField = createDropdownField(
          field.key,
          field.label as string,
          [
            // Include all existing options except 'Custom...'
            ...(existingOptions ?? []).filter(
              (opt) => opt.value !== '_custom_',
            ),
            // Add the new custom value
            { label: customValue, value: customValue },
            // Add back the Custom... option at the end
            { label: 'Custom...', value: '_custom_' },
          ],
          customValue, // Set the new value as selected
          {
            name: field.name,
            props: field.props,
            events: field.events,
          },
        );

        // Replace the field in the array
        this.formFields[fieldIndex] = updatedField;

        // Trigger form rebuild
        this.formFields = [...this.formFields];
      }

      // Close the modal
      this.isCustomInputModalOpen = false;
      this.currentEditField = null;
    }
  }

  override transformFormData(formData: Record<string, string | boolean>) {
    if (this.injectDataAtPath()) {
      const result = {};
      setNestedProperty(result, this.dataPath(), formData);
      return result;
    } else {
      return formData;
    }
  }
}
