import { Injectable, inject } from '@angular/core';
import { Observable } from 'rxjs';
import {
  DeviceProviderListItem,
  DeviceProviderListResponse,
  DeviceProviderResponse,
  DeviceProvidersService,
} from '../../../../api';
import { GridDataService } from '../../../../shared/models';

@Injectable({
  providedIn: 'root',
})
export class DeviceProvidersDataAdapter
  implements GridDataService<DeviceProviderListItem>
{
  private readonly service = inject(DeviceProvidersService);

  getList(params: {
    owner: string;
    offset: number;
    page: number;
    limit: number;
    sortField?: string;
    sortOrder?: number;
    filters?: string;
    recurse?: boolean;
  }): Observable<DeviceProviderListResponse> {
    return this.service.listDeviceProviders(
      params.owner,
      params.recurse,
      params.offset,
      params.limit,
      params.sortField,
      params.filters,
    );
  }

  getById(id: string): Observable<DeviceProviderResponse> {
    return this.service.getDeviceProvider(id);
  }
}
