import { Component, computed, inject, input, signal } from '@angular/core';

import { MessageModule } from 'primeng/message';
import { ProgressSpinnerModule } from 'primeng/progressspinner';

import {
  VendorListItem,
  VendorResponse,
  VendorCreateRequest,
  AccountsService,
} from '../../../../../api';
import { isNullOrUndefined } from '../../../../../shared/utils';
import { EntityDetailsStateService } from '../../../services/entity/entity-details.state.service';
import { EntityOperationRegistryService } from '../../../services/entity/entity-operation-registry.service';
import { DetailsAccordionContainerComponent } from '../../details-accordion-container/details-accordion-container.component';
import { VendorSectionConfigFactory } from '../../../factories';

@Component({
  selector: 'app-distributor-vendor-details-container',
  imports: [
    DetailsAccordionContainerComponent,
    ProgressSpinnerModule,
    MessageModule,
  ],
  templateUrl: './distributor-vendor-details-container.component.html',
  styleUrl: './distributor-vendor-details-container.component.scss',
})
export class DistributorVendorDetailsContainerComponent {
  readonly entity = input<VendorListItem | null>(null);

  private readonly vendorSectionFactory = inject(VendorSectionConfigFactory);
  readonly entityDetailsState = inject(EntityDetailsStateService);
  private readonly accountsService = inject(AccountsService);
  private readonly operationRegistry = inject(EntityOperationRegistryService);

  readonly isLoading = computed(() => this.entityDetailsState.isLoading());
  readonly isSoftRefreshing = computed(() =>
    this.entityDetailsState.isSoftRefreshing(),
  );
  readonly isInitialLoading = computed(
    () => this.isLoading() && !this.isSoftRefreshing() && !this.fullVendor(),
  );
  readonly fullVendor = computed(() => {
    const entityDetails = this.entityDetailsState.selectedItem();

    if (isNullOrUndefined(entityDetails)) {
      return null;
    }
    return entityDetails as VendorResponse;
  });
  readonly sections = computed(() => {
    const vendor = this.fullVendor();
    if (isNullOrUndefined(vendor)) return [];

    return this.vendorSectionFactory.createAllVendorSections(vendor);
  });
  readonly error = signal<string | null>(null);

  constructor() {
    this.operationRegistry.registerEntityOperations('vendor', {
      update: (id, data) => this.accountsService.updateVendor(id, data),
      create: (data: VendorCreateRequest) =>
        this.accountsService.createVendor(data),
      get: (id) => this.accountsService.getVendor(id),
    });
  }

  onEntityChange(entity: unknown): void {
    this.entityDetailsState.updateEntity(entity as VendorResponse);
    this.error.set(null);
  }
}
