import { CommonModule } from '@angular/common';
import {
  Component,
  computed,
  effect,
  inject,
  input,
  signal,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { Validators } from '@angular/forms';

import { ButtonModule } from 'primeng/button';
import { MessageModule } from 'primeng/message';
import { v4 as uuidv4 } from 'uuid';

import {
  AssetRatingProfileListItem,
  AssetRatingProfileCreateRequest,
  EntitiesService,
  AssetRatingPenalty,
} from '../../../../../api';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { ModalListFormComponent } from '../../../../../shared/components/forms/modal-list-form/modal-list-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import {
  ListFieldModalConfig,
  FormFieldConfig,
  createTextField,
  createNumberField,
  createModalListField,
  createEventFilterField,
} from '../../../../../shared/models';
import { MeasurementUnitsService } from '../../../../../shared/services/measurement-units/measurement-units.service';
import {
  isDefined,
  isEmpty,
  isNullOrUndefined,
} from '../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../base';

@Component({
  selector: 'app-asset-rating-profile-details-section',
  imports: [
    CommonModule,
    ButtonModule,
    GridComponent,
    DynamicFormComponent,
    MessageModule,
  ],
  templateUrl: './asset-rating-profile-details-section.component.html',
  styleUrl: './asset-rating-profile-details-section.component.scss',
})
export class AssetRatingProfileDetailsSectionComponent extends EntitySectionBaseComponent<
  AssetRatingProfileListItem | AssetRatingProfileCreateRequest
> {
  readonly ownerId = input<string | null>(null);
  private readonly entitiesService = inject(EntitiesService);
  private readonly measurementUnitsService = inject(MeasurementUnitsService);

  readonly assetRatingProfileDetails = computed(() => {
    const assetRatingProfileDetails = this.entity();
    if (!isDefined(assetRatingProfileDetails)) return [];

    return [
      { key: 'Name', value: assetRatingProfileDetails.name },
      {
        key: 'Penalties',
        value: !isEmpty(assetRatingProfileDetails.items)
          ? assetRatingProfileDetails.items?.map((item) => item.name).join(', ')
          : 'None',
      },
    ];
  });
  assetRatingProfilePenaltyModalConfig:
    | ListFieldModalConfig<AssetRatingPenalty>
    | undefined;
  protected readonly warning = signal<string | null>(null);

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    effect(() => {
      const assetRatingProfileDetails = this.entity();
      if (
        isNullOrUndefined(assetRatingProfileDetails?.items) ||
        assetRatingProfileDetails.items.length < 1
      ) {
        this.warning.set(
          'At least one penalty is required for the asset rating profile to be useful.',
        );
      } else {
        this.warning.set(null);
      }
    });
  }

  protected override updateFormFields(): void {
    const assetRatingProfile = this.entity();

    this.assetRatingProfilePenaltyModalConfig = {
      modalComponent: ModalListFormComponent,
      modalTitle: 'Rating Penalty',
      defaultItemProvider: () => ({
        id: uuidv4(),
        name: '',
        max: 100,
        offset: undefined,
        penalty: 1,
        cost: undefined,
      }),
      listItemFormatter: (item: AssetRatingPenalty) =>
        this.stateItemToListItem(item),
      modalFields: (
        _item: AssetRatingPenalty | undefined,
      ): FormFieldConfig[] => {
        return [
          createTextField('id', 'ID', _item?.id, {
            name: 'id',
            hidden: true,
          }),
          createTextField('name', 'Name', _item?.name, {
            name: 'name',
            validations: [
              {
                name: 'required',
                validator: Validators.required,
                message: 'Name is required',
              },
            ],
          }),
          createNumberField('penalty', 'Penalty', undefined, {
            name: 'penalty',
            validations: [
              {
                name: 'required',
                validator: Validators.required,
                message: 'Penalty is required',
              },
              {
                name: 'min',
                validator: Validators.min(1),
                message: 'Min must be 1 or greater',
              },
              {
                name: 'max',
                validator: Validators.max(100),
                message: 'Max must be 100 or less',
              },
            ],
            layout: 'horizontal',
            labelWidth: '1/3',
          }),
          createNumberField('max', 'Max', undefined, {
            name: 'max',
            validations: [
              {
                name: 'required',
                validator: Validators.required,
                message: 'Max is required',
              },
              {
                name: 'min',
                validator: Validators.min(1),
                message: 'Min must be 1 or greater',
              },
              {
                name: 'max',
                validator: Validators.max(100),
                message: 'Max must be 100 or less',
              },
            ],
            layout: 'horizontal',
            labelWidth: '1/3',
          }),
          createNumberField('cost', 'Cost', undefined, {
            name: 'cost',
            validations: [
              {
                name: 'required',
                validator: Validators.required,
                message: 'Cost is required',
              },
              {
                name: 'min',
                validator: Validators.min(0),
                message: 'Min must be 0 or greater',
              },
              {
                name: 'max',
                validator: Validators.max(1000000),
                message: 'Max must be 1000000 or less',
              },
            ],
            layout: 'horizontal',
            labelWidth: '1/3',
          }),
          createEventFilterField(
            'filter',
            'Event Filter',
            undefined,
            ['costcentres', 'groups', 'types'],
            {
              name: 'filter',
              required: true,
              validations: [
                {
                  name: 'required',
                  validator: Validators.required,
                  message: 'Event filter is required',
                },
              ],
            },
          ),
        ];
      },
      subHeader:
        'Choose penalty severity and configure the event filter to trigger this penalty.',
    };
    this.formFields = [
      createTextField('name', 'Name', assetRatingProfile?.name, {
        name: 'name',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'Name is required',
          },
        ],
      }),
    ];

    if (!this.createMode()) {
      this.formFields.push(
        createModalListField<AssetRatingPenalty>(
          'items',
          'Penalties',
          assetRatingProfile?.items ?? [],
          {
            layout: 'horizontal',
            labelWidth: '1/3',
            name: 'items',
            props: {
              modalConfig: this
                .assetRatingProfilePenaltyModalConfig as unknown as ListFieldModalConfig<unknown>,
            },
          },
        ),
      );
    }
  }

  protected override submitChanges(
    formData: Record<string, string | number>,
  ): void {
    const assetRatingProfile = this.entity();
    if (isNullOrUndefined(assetRatingProfile)) return;
    this.entitiesService
      .updateAssetRatingProfile(assetRatingProfile.id, formData)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: (response) => {
          this.isFormEditable.set(false);
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'asset-rating-profile',
            operation: 'update',
            entityId: assetRatingProfile.id,
            data: response,
          });
        },
        error: () => {
          this.isFormEditable.set(true);
        },
      });
  }

  stateItemToListItem(item: AssetRatingPenalty) {
    const costString = item.cost ? `, cost ${item.cost}` : '';
    const display = `${item.penalty} (${item.max} max${costString})`;
    return {
      id: item.id,
      title: item.name,
      display,
      icon: 'pi pi-star',
    };
  }
}
