import {
  Component,
  computed,
  effect,
  inject,
  OnInit,
  signal,
  WritableSignal,
} from '@angular/core';
import { CommonModule } from '@angular/common';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { FormGroup, Validators } from '@angular/forms';
import { HttpClient } from '@angular/common/http';
import { catchError, finalize, forkJoin, Observable, of } from 'rxjs';

import { InputTextModule } from 'primeng/inputtext';
import { ButtonModule } from 'primeng/button';
import { SplitButtonModule } from 'primeng/splitbutton';
import { DataViewModule } from 'primeng/dataview';
import { CardModule } from 'primeng/card';
import { MenuItem } from 'primeng/api';

import {
  AssetResponse,
  EntitiesService,
  ReminderListItem,
  ReminderReset,
  ReminderCreateRequest,
} from '../../../../../api';
import {
  createDropdownField,
  createTextField,
  createDateField,
  FormFieldConfig,
  createNumberField,
  FormAction,
  createListboxField,
} from '../../../../../shared/models';
import {
  isDefined,
  isEmpty,
  isNullOrUndefined,
} from '../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../base';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';

import {
  DAY_OF_MONTH_OPTIONS,
  MONTH_OPTIONS,
  ReminderType, // UI Enum
  WEEKDAY_OPTIONS,
} from '../../../models';
import { DynamicFormModalComponent } from '../../../../../shared/components/forms/dynamic-form-modal/dynamic-form-modal.component';
import { AuthDataService } from '../../../../../core/services/auth-data.service';
import { ApiSchemaService } from '../../../../../core/services/api-schema.service';

// Helper for month/day name to number conversion
const MONTH_NAME_TO_NUMBER: Record<string, number> = {
  JANUARY: 1,
  FEBRUARY: 2,
  MARCH: 3,
  APRIL: 4,
  MAY: 5,
  JUNE: 6,
  JULY: 7,
  AUGUST: 8,
  SEPTEMBER: 9,
  OCTOBER: 10,
  NOVEMBER: 11,
  DECEMBER: 12,
};
const WEEKDAY_NAME_TO_NUMBER: Record<string, number> = {
  SUNDAY: 0,
  MONDAY: 1,
  TUESDAY: 2,
  WEDNESDAY: 3,
  THURSDAY: 4,
  FRIDAY: 5,
  SATURDAY: 6,
};

@Component({
  selector: 'app-asset-reminders-section',
  imports: [
    CommonModule,
    ButtonModule,
    InputTextModule,
    GridComponent,
    DynamicFormModalComponent,
    SplitButtonModule,
    DataViewModule,
    CardModule,
  ],
  templateUrl: './asset-reminders-section.component.html',
  styleUrl: './asset-reminders-section.component.scss',
})
export class AssetRemindersSectionComponent
  extends EntitySectionBaseComponent<AssetResponse>
  implements OnInit
{
  private readonly entitiesService = inject(EntitiesService);
  private readonly http = inject(HttpClient);
  private readonly authDataService = inject(AuthDataService);
  private readonly apiSchemaService = inject(ApiSchemaService);

  readonly isLoadingAsset = signal<boolean>(false);
  private readonly remindersData = signal<ReminderListItem[]>([]);

  readonly showReminderModal = signal<boolean>(false);
  readonly currentModalTitle = signal<string>('Add Reminder');
  readonly currentReminderType: WritableSignal<ReminderType | null> =
    signal<ReminderType | null>(null);
  readonly currentFormFields: WritableSignal<FormFieldConfig[]> = signal<
    FormFieldConfig[]
  >([]);

  private newReminders: Partial<ReminderListItem>[] = [];
  private deletedReminderIds: string[] = [];
  private loadedAssetId: string | null = null;

  reminderOptions: MenuItem[] = [
    {
      label: 'Odometer Reminder',
      command: () => this.openReminderModal(ReminderType.ODOMETER),
    },
    {
      label: 'Engine Hours Reminder',
      command: () => this.openReminderModal(ReminderType.ENGINE_HOURS),
    },
    {
      label: 'Time Based Reminder',
      command: () => this.openReminderModal(ReminderType.TIME_BASED),
    },
  ];

  readonly reminders = computed(() => {
    const remindersList = this.remindersData();
    return [
      {
        key: 'Reminders',
        value: isEmpty(remindersList)
          ? 'None'
          : remindersList.map((r) => r.name).join(', '),
      },
    ];
  });

  readonly sortedReminders = computed(() => {
    const combined = [
      ...this.remindersData(),
      ...this.newReminders.filter(
        (r) => !this.deletedReminderIds.includes(r.id ?? ''),
      ),
    ];
    return combined.sort((a, b) => {
      const dateA =
        a.modifiedDate ??
        ((a.id?.startsWith('temp-') ?? false) ? Date.now() : 0);
      const dateB =
        b.modifiedDate ??
        ((b.id?.startsWith('temp-') ?? false) ? Date.now() : 0);
      // Ensure dateA and dateB are numbers before getTime()
      const timeA =
        typeof dateA === 'string' ? new Date(dateA).getTime() : Number(dateA);
      const timeB =
        typeof dateB === 'string' ? new Date(dateB).getTime() : Number(dateB);
      return timeB - timeA;
    });
  });

  readonly hasChanges = computed(
    () => this.newReminders.length > 0 || this.deletedReminderIds.length > 0,
  );

  override readonly actions: FormAction[] = [
    {
      label: 'Cancel',
      action: () => {
        this.showReminderModal.set(false);
        this.resetCurrentReminder();
      },
      severity: 'secondary',
    },
    {
      label: 'Ok',
      action: (formData: unknown) => {
        this.onReminderSubmit(formData as Record<string, unknown>);
      },
      severity: 'primary',
      disabled: (form?: FormGroup) =>
        (form?.invalid ?? false) ||
        ((form?.dirty ?? false) && !(form?.touched ?? false)) ||
        this.isLoadingAsset(),
    },
  ];

  timezones: { label: string; value: string }[] = [];

  constructor() {
    super();
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];
    effect(() => {
      const asset = this.entity();
      if (isDefined(asset?.id) && isDefined(asset?.owner?.id)) {
        if (asset.id !== this.loadedAssetId) this.loadReminders(asset);
      } else {
        this.remindersData.set([]);
        this.loadedAssetId = null;
        this.resetChanges();
      }
    });
  }

  ngOnInit(): void {
    this.loadTimezones();
  }

  override updateFormFields(): void {
    // No-op for now
  }

  private loadReminders(asset: AssetResponse): void {
    if (this.isLoadingAsset() || !asset.id || !asset.owner?.id) return;
    this.loadedAssetId = asset.id;
    this.isLoadingAsset.set(true);
    this.entitiesService
      .listReminders(asset.owner.id, asset.id)
      .pipe(
        takeUntilDestroyed(this.destroyRef),
        catchError(() => of({ items: [], count: 0 })),
        finalize(() => this.isLoadingAsset.set(false)),
      )
      .subscribe({
        next: (res) => {
          this.remindersData.set(res.items ?? []);
          this.resetChanges();
        },
      });
  }

  private loadTimezones(): void {
    this.http
      .get<{ id: string; name: string }[]>('/assets/docs/timezones.json')
      .subscribe((data) => {
        this.timezones = data
          .map((tz) => ({ label: tz.id, value: tz.id }))
          .sort((a, b) => a.label.localeCompare(b.label));
      });
  }

  private resetChanges(): void {
    this.newReminders = [];
    this.deletedReminderIds = [];
  }

  private resetCurrentReminder(): void {
    this.currentReminderType.set(null);
    this.currentModalTitle.set('Add Reminder');
    this.currentFormFields.set([]);
  }

  openReminderModal(type: ReminderType): void {
    this.currentReminderType.set(type);
    let title = 'Add Reminder';
    if (type === ReminderType.ODOMETER) title = 'Add Odometer Reminder';
    else if (type === ReminderType.ENGINE_HOURS)
      title = 'Add Engine Hours Reminder';
    else if (type === ReminderType.TIME_BASED)
      title = 'Add Time Based Reminder';
    this.currentModalTitle.set(title);
    this.currentFormFields.set(this._generateFormFields(type));
    this.showReminderModal.set(true);
  }

  onReminderSubmit(formData: Record<string, unknown>): void {
    const uiReminderType = this.currentReminderType();
    if (isNullOrUndefined(uiReminderType)) {
      console.error('Current reminder type is not set.');
      this.closeReminderModal();
      return;
    }

    const apiTypeValue = this.mapUiTypeToApiType(uiReminderType);
    if (apiTypeValue === null) {
      console.error('Unknown UI reminder type:', uiReminderType);
      this.closeReminderModal();
      return;
    }

    const newReminder = this.createBaseReminder(formData, apiTypeValue);
    this.setReminderTrigger(newReminder, formData, uiReminderType);
    this.setReminderReset(newReminder, formData);
    this.setReminderTimeZone(newReminder, formData, uiReminderType);

    this.newReminders = [...this.newReminders, newReminder];
    this.closeReminderModal();
  }

  private closeReminderModal(): void {
    this.showReminderModal.set(false);
    this.resetCurrentReminder();
  }

  private mapUiTypeToApiType(
    uiType: ReminderType,
  ): ReminderListItem.TypeEnum | null {
    switch (uiType) {
      case ReminderType.ODOMETER:
        return ReminderListItem.TypeEnum.Odo;
      case ReminderType.ENGINE_HOURS:
        return ReminderListItem.TypeEnum.Hours;
      case ReminderType.TIME_BASED:
        return ReminderListItem.TypeEnum.Time;
      default:
        return null;
    }
  }

  private createBaseReminder(
    formData: Record<string, unknown>,
    apiTypeValue: ReminderListItem.TypeEnum,
  ): Partial<ReminderListItem> & { id: string; name: string } {
    const tempId = 'temp-' + Date.now();
    const reminderName = formData['name'] as string;

    const newReminder: Partial<ReminderListItem> & {
      id: string;
      name: string;
    } = {
      id: tempId,
      name: reminderName,
      mode: formData['mode'] as ReminderListItem.ModeEnum,
    };

    this.apiSchemaService.setEntityType<
      Partial<ReminderListItem>,
      ReminderListItem.TypeEnum
    >(newReminder, 'Reminder', apiTypeValue);
    return newReminder;
  }

  private setReminderTrigger(
    reminder: Partial<ReminderListItem>,
    formData: Record<string, unknown>,
    uiReminderType: ReminderType,
  ): void {
    const formTriggerGroup = formData['trigger'] as
      | { start?: string; value?: number }
      | undefined;

    if (
      uiReminderType === ReminderType.TIME_BASED &&
      typeof formTriggerGroup?.start === 'string' &&
      formTriggerGroup.start.length > 0
    ) {
      reminder.trigger = { start: formTriggerGroup.start };
    } else if (
      (uiReminderType === ReminderType.ODOMETER ||
        uiReminderType === ReminderType.ENGINE_HOURS) &&
      isDefined(formTriggerGroup?.value)
    ) {
      reminder.trigger = { value: String(formTriggerGroup.value) };
    }
  }

  private setReminderReset(
    reminder: Partial<ReminderListItem>,
    formData: Record<string, unknown>,
  ): void {
    const resetType = formData['resetType'] as string | undefined;
    const formResetGroup = formData['reset'] as
      | Record<string, unknown>
      | undefined;
    const formTimeZoneId = formData['timeZoneId'] as string | null | undefined;

    if (
      typeof resetType === 'string' &&
      resetType !== 'none' &&
      formResetGroup
    ) {
      const apiResetPayload = this.buildResetPayload(resetType, formResetGroup);
      if (apiResetPayload) {
        // Add timezone to reset payload if available
        if (typeof formTimeZoneId === 'string' && formTimeZoneId.length > 0) {
          apiResetPayload['timeZoneId'] = formTimeZoneId;
        }
        reminder.reset = apiResetPayload;
      }
    }
  }

  private buildResetPayload(
    resetType: string,
    formResetGroup: Record<string, unknown>,
  ): ReminderReset | null {
    const apiResetPayload: ReminderReset = {
      type: resetType as ReminderReset.TypeEnum,
    };
    let resetConfigFound = false;
    const resetDetails = formResetGroup[resetType] as
      | Record<string, unknown>
      | undefined;

    if (resetDetails) {
      resetConfigFound = this.setResetTypeConfig(
        apiResetPayload,
        resetType,
        resetDetails,
      );
    }

    const counterValue = formResetGroup['counter'] as string | undefined;
    if (typeof counterValue === 'string' && counterValue.length > 0) {
      apiResetPayload.counter = parseInt(
        counterValue.replace('counter_cnt_', ''),
        10,
      );
    }

    return resetConfigFound || isDefined(apiResetPayload.counter)
      ? apiResetPayload
      : null;
  }

  private setResetTypeConfig(
    payload: ReminderReset,
    resetType: string,
    resetDetails: Record<string, unknown>,
  ): boolean {
    switch (resetType) {
      case 'daily':
        payload.daily = { recurrence: Number(resetDetails['recurrence']) };
        return true;
      case 'weekly':
        payload.weekly = {
          days: (resetDetails['days'] as string[])
            .map((d) => WEEKDAY_NAME_TO_NUMBER[d])
            .filter(isDefined),
        };
        return true;
      case 'monthly':
        payload.monthly = {
          months: (resetDetails['months'] as string[])
            .map((m) => MONTH_NAME_TO_NUMBER[m])
            .filter(isDefined),
          day: Number(resetDetails['day']),
        };
        return true;
      default:
        return false;
    }
  }

  private setReminderTimeZone(
    reminder: Partial<ReminderListItem>,
    formData: Record<string, unknown>,
    uiReminderType: ReminderType,
  ): void {
    const formTimeZoneId = formData['timeZoneId'] as string | null | undefined;

    if (
      uiReminderType === ReminderType.TIME_BASED &&
      typeof formTimeZoneId === 'string' &&
      formTimeZoneId.length > 0
    ) {
      reminder.timeZoneId = formTimeZoneId;
      if (
        reminder.reset &&
        typeof reminder.reset['timeZoneId'] === 'undefined'
      ) {
        reminder.reset['timeZoneId'] = formTimeZoneId;
      }
    }
  }

  private isValidNonEmptyString(value: unknown): value is string {
    return typeof value === 'string' && value.length > 0;
  }

  deleteReminder(reminderToDelete: Partial<ReminderListItem>): void {
    if (
      typeof reminderToDelete.id === 'string' &&
      reminderToDelete.id.startsWith('temp-')
    ) {
      this.newReminders = this.newReminders.filter(
        (r) => r.id !== reminderToDelete.id,
      );
    } else if (
      typeof reminderToDelete.id === 'string' &&
      reminderToDelete.id.length > 0
    ) {
      this.deletedReminderIds = [
        ...this.deletedReminderIds,
        reminderToDelete.id,
      ];
      this.remindersData.set(
        this.remindersData().filter((r) => r.id !== reminderToDelete.id),
      );
    }
  }

  saveChanges(): void {
    const entity = this.entity();
    const ownerId = entity?.owner?.id;
    const assetId = entity?.id;

    if (
      !this.isValidNonEmptyString(ownerId) ||
      !this.isValidNonEmptyString(assetId)
    ) {
      console.error('Asset owner or ID is missing or invalid.');
      return;
    }

    this.isLoadingAsset.set(true);
    const operations: Observable<unknown>[] = []; // Use unknown instead of any

    this.newReminders.forEach((r) => {
      // Keep only fields relevant to ReminderCreateRequest, excluding those handled by IDs or generated by backend.
      const {
        id: _id,
        owner: _owner,
        target: _target,
        modifiedDate: _modifiedDate,
        enabled: _enabled,
        createdDate: _createdDate,
        ...relevantFieldsFromR
      } = r;

      const typePropertyName =
        this.apiSchemaService.getEntityTypePropertyName('Reminder');
      const typeValue = (relevantFieldsFromR as Record<string, unknown>)[
        typePropertyName
      ];

      const createApiRequestBody: ReminderCreateRequest = {
        ...(relevantFieldsFromR as Omit<
          Partial<ReminderListItem>,
          'id' | 'owner' | 'target' | 'modifiedDate' | 'enabled' | 'createdDate'
        >),
        name: r.name, // name is required in our temp object
        ownerId: ownerId, // guaranteed to be string by type guard
        targetId: assetId, // guaranteed to be string by type guard
        [typePropertyName]: typeValue as ReminderListItem.TypeEnum, // Add dynamic type property
      };

      // Clean up undefined optional fields to avoid sending them as nulls if not intended
      if (createApiRequestBody.timeZoneId === undefined)
        delete createApiRequestBody.timeZoneId;
      if (createApiRequestBody.trigger === undefined)
        delete createApiRequestBody.trigger;
      if (createApiRequestBody.reset === undefined)
        delete createApiRequestBody.reset;
      if (createApiRequestBody.mode === undefined)
        delete createApiRequestBody.mode;

      operations.push(
        this.entitiesService.createReminder(createApiRequestBody).pipe(
          catchError((err) => {
            console.error('Error creating reminder:', r.name, err);
            return of(null);
          }),
        ),
      );
    });

    this.deletedReminderIds.forEach((id) =>
      operations.push(
        this.entitiesService
          .deleteReminder(id) // Pass only the ID string
          .pipe(
            catchError((err) => {
              console.error('Error deleting reminder:', id, err);
              return of(null);
            }),
          ),
      ),
    );

    if (operations.length > 0) {
      forkJoin(operations)
        .pipe(
          finalize(() => {
            this.isLoadingAsset.set(false);
            this.resetChanges();
            if (this.entity())
              this.loadReminders(this.entity() as AssetResponse);
          }),
        )
        .subscribe((_results) => {
          /* Save complete */
        });
    } else {
      this.isLoadingAsset.set(false);
    }
  }

  public getReminderTypeForDisplay(
    reminder: Partial<ReminderListItem>,
  ): string {
    const typeValue = this.apiSchemaService.getEntityType(
      reminder as { id: string; name: string },
      'Reminder',
    ) as ReminderListItem.TypeEnum | null | undefined;
    if (isNullOrUndefined(typeValue)) return 'N/A';
    switch (typeValue) {
      case ReminderListItem.TypeEnum.Time:
        return 'Time Based';
      case ReminderListItem.TypeEnum.Odo:
        return 'Odometer';
      case ReminderListItem.TypeEnum.Hours:
        return 'Engine Hours';
      default: {
        return 'Unknown (' + (typeValue as string) + ')';
      }
    }
  }

  private createResetCounterOptions(
    _type: ReminderType,
  ): { label: string; value: string }[] {
    const prefix = 'counter';
    return Array.from({ length: 8 }, (_, i) => ({
      label: prefix + '_cnt_' + (i + 1),
      value: prefix + '_cnt_' + (i + 1),
    }));
  }

  private _generateFormFields(type: ReminderType): FormFieldConfig[] {
    const base: FormFieldConfig[] = [
      createTextField('name', 'Name', '', {
        name: 'name',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'Name required',
          },
        ],
      }),
      createDropdownField(
        'mode',
        'Mode',
        [
          { label: 'Once', value: ReminderListItem.ModeEnum.Once },
          { label: 'Repeating', value: ReminderListItem.ModeEnum.Repeating },
        ],
        ReminderListItem.ModeEnum.Once,
        { name: 'mode', props: { appendTo: 'body' } },
      ),
    ];
    if (type === ReminderType.ODOMETER || type === ReminderType.ENGINE_HOURS) {
      base.push({
        name: 'trigger',
        key: 'trigger',
        type: 'group',
        fields: [
          createNumberField('value', 'Trigger At', 0, {
            name: 'value',
            validations: [
              {
                name: 'required',
                validator: Validators.required,
                message: 'Trigger value required',
              },
            ],
            props: {
              suffix: type === ReminderType.ODOMETER ? ' km/mi' : ' hours',
            },
          }),
        ],
      });
      base.push(this.createResetTypeDropdown(type));
    } else if (type === ReminderType.TIME_BASED) {
      base.push({
        name: 'trigger',
        key: 'trigger',
        type: 'group',
        fields: [
          createDateField('start', 'Starting at', '', {
            name: 'start',
            validations: [
              {
                name: 'required',
                validator: Validators.required,
                message: 'Start date required',
              },
            ],
            props: {
              appendTo: 'body',
              showTime: true,
              showSeconds: true,
              dateFormat: 'yy/mm/dd',
            },
          }),
        ],
      });
      base.push(
        createDropdownField(
          'timeZoneId',
          'Timezone',
          this.timezones,
          this.authDataService.getUserProfile()?.timeZoneId ?? null,
          {
            name: 'timeZoneId',
            placeholder: 'Select timezone',
            props: { appendTo: 'body' },
            validations: [
              {
                name: 'required',
                validator: Validators.required,
                message: 'Timezone required',
              },
            ],
          },
        ),
      );
      base.push(this.createResetTypeDropdown(type));
    }
    return base;
  }

  private createResetConfig(
    resetType: 'daily' | 'weekly' | 'monthly',
    uiType: ReminderType,
  ): FormFieldConfig[] {
    const counters = this.createResetCounterOptions(uiType);
    const config: FormFieldConfig[] = [];
    if (resetType === 'daily')
      config.push(
        createNumberField('recurrence', 'Every', 1, {
          name: 'recurrence',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: 'Recurrence required',
            },
          ],
          props: { suffix: ' Days' },
        }),
      );
    else if (resetType === 'weekly')
      config.push(
        createListboxField('days', 'Weekdays', [], WEEKDAY_OPTIONS, {
          name: 'days',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: 'Weekdays required',
            },
          ],
          props: { checkmark: true, multiple: true },
        }),
      );
    else if (resetType === 'monthly') {
      config.push(
        createListboxField('months', 'Months', [], MONTH_OPTIONS, {
          name: 'months',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: 'Months required',
            },
          ],
          props: { checkmark: true, multiple: true },
        }),
      );
      config.push(
        createDropdownField(
          'day',
          'Day',
          DAY_OF_MONTH_OPTIONS,
          DAY_OF_MONTH_OPTIONS[0]?.value ?? null,
          {
            name: 'day',
            validations: [
              {
                name: 'required',
                validator: Validators.required,
                message: 'Day required',
              },
            ],
            props: { appendTo: 'body' },
          },
        ),
      );
    }
    config.push(
      createDropdownField(
        'counter',
        'Reset Counter',
        counters,
        counters[0]?.value ?? null,
        {
          name: 'counter',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: 'Counter required',
            },
          ],
          props: { appendTo: 'body' },
        },
      ),
    );
    return config;
  }

  private createResetTypeDropdown(uiType: ReminderType): FormFieldConfig {
    return createDropdownField(
      'resetType',
      'Reset',
      [
        { label: 'After each reminder', value: 'none' },
        { label: 'Daily', value: 'daily' },
        { label: 'Weekly', value: 'weekly' },
        { label: 'Monthly', value: 'monthly' },
      ],
      'none',
      {
        name: 'resetType',
        conditional: true, // Removed conditionsWrapper
        conditions: {
          none: [],
          daily: this.createResetConfig('daily', uiType),
          weekly: this.createResetConfig('weekly', uiType),
          monthly: this.createResetConfig('monthly', uiType),
        },
        props: { appendTo: 'body' },
      },
    );
  }
}
