import {
  Component,
  computed,
  effect,
  inject,
  input,
  Signal,
  signal,
} from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';

import {
  AssetListItem,
  EntitiesService,
  TelemetryStateResponse,
} from '../../../../../api';
import {
  createDateField,
  createNumberField,
  MeasurementUnitType,
} from '../../../../../shared/models';
import {
  isDefined,
  isEmpty,
  isNullOrUndefined,
} from '../../../../../shared/utils';
import { EntitySectionBaseComponent } from '../../base';
import { MeasurementUnitsService } from '../../../../../shared/services/measurement-units/measurement-units.service';
import { CommonModule } from '@angular/common';
import { ButtonModule } from 'primeng/button';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';

@Component({
  selector: 'app-asset-counter-type-section',
  imports: [CommonModule, ButtonModule, GridComponent, DynamicFormComponent],
  templateUrl: './asset-counter-type-section.component.html',
  styleUrl: './asset-counter-type-section.component.scss',
})
export class AssetCounterTypeSectionComponent extends EntitySectionBaseComponent<AssetListItem> {
  counterType = input<'hours' | 'odometer'>('hours');
  private readonly entitiesService = inject(EntitiesService);
  private readonly measurementsService = inject(MeasurementUnitsService);
  private readonly assetLocation = signal<TelemetryStateResponse | null>(null);

  private formatDateString(dateString: string | undefined): string {
    if (!isDefined(dateString)) return '';

    try {
      const date = new Date(dateString);
      if (isNaN(date.getTime())) {
        return 'Invalid Date';
      }

      return date.toLocaleDateString(undefined, {
        weekday: 'long',
        day: 'numeric',
        month: 'long',
      });
    } catch (e) {
      console.error('Error parsing date:', e);
      return 'Invalid Date';
    }
  }

  private formatCounterValue(value: number): number {
    if (this.counterType() === 'odometer') {
      return this.measurementsService.fromBackend(
        MeasurementUnitType.DISTANCE,
        value,
        1,
      );
    }
    if (this.counterType() === 'hours') {
      return Math.round(value * 10) / 10;
    }
    return value;
  }

  private getCounterLabel(): string {
    return this.counterType() === 'odometer' ? 'Odometer' : 'Engine Hours';
  }

  readonly assetDetails = computed(() => {
    const assetDetails = this.entity();
    if (!isDefined(assetDetails)) return [];

    const location = this.assetLocation();
    if (isEmpty(location?.['counters'])) return [];

    const rawValue = location?.['counters']?.[this.counterType()] ?? 0;
    const value = this.formatCounterValue(rawValue);
    const formattedDate = this.formatDateString(location?.['date']);

    return [
      {
        key: this.getCounterLabel(),
        value: value,
      },
      {
        key: 'Date',
        value: formattedDate,
      },
    ];
  });
  override sectionTitle: Signal<string> = signal<string>(
    this.counterType() === 'odometer' ? 'Odometer' : 'Engine Hours',
  );

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    // React to entity changes
    effect(() => {
      const assetDetails = this.entity();
      if (assetDetails) {
        this.loadAssetLocation(assetDetails.id);
      }
    });

    effect(() => {
      const assetDetails = this.entity();
      if (assetDetails) {
        this.updateFormFields();
      }
    });
  }

  private loadAssetLocation(assetId: string): void {
    this.entitiesService
      .getAssetLocation(assetId)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe((location) => {
        this.assetLocation.set(location);
      });
  }

  protected override updateFormFields(): void {
    const location = this.assetLocation();
    let value = location?.['counters']?.[this.counterType()] ?? 0;
    const dateString = location?.['date'];
    const initialDateValue = isDefined(dateString)
      ? new Date(dateString)
      : null;
    if (this.counterType() === 'odometer') {
      value = this.measurementsService.fromBackend(
        MeasurementUnitType.DISTANCE,
        value,
        1,
      );
    }
    if (this.counterType() === 'hours') {
      value = Math.round(value * 10) / 10;
    }
    this.formFields = [
      createNumberField(
        'value',
        this.counterType() === 'odometer' ? 'Odometer' : 'Engine Hours',
        value,
        {
          name: 'value',
          props: {
            suffix:
              this.counterType() === 'odometer'
                ? this.measurementsService.getUnitConfig(
                    MeasurementUnitType.DISTANCE,
                  )
                : 'hours',
          },
        },
      ),

      createDateField('date', 'Date', initialDateValue, {
        name: 'date',
        props: {
          showTime: true,
          timeOnly: false,
          dateFormat: 'mm/dd/yy',
          hourFormat: '24',
          showIcon: true,
          appendTo: 'body',
        },
      }),
    ];
  }

  protected override submitChanges(
    formData: Record<string, string | number>,
  ): void {
    const asset = this.entity();
    if (isNullOrUndefined(asset)) return;
    this.entitiesService
      .updateAsset(asset.id, formData)
      .pipe(takeUntilDestroyed(this.destroyRef))
      .subscribe({
        next: () => {
          this.isFormEditable.set(false);
          this.broadcastService.broadcast('entity-updated', {
            entityType: 'asset',
            entityId: asset.id,
          });
        },
        error: () => {
          this.isFormEditable.set(true);
        },
      });
  }

  protected override onFormValueChange(
    formData: Record<string, unknown>,
  ): void {
    const transformedData = { ...formData };

    // Transform counterTypes to array of objects with id and name
    if (isDefined(transformedData['value'])) {
      if (this.counterType() === 'odometer') {
        transformedData['value'] = this.measurementsService.toBackend(
          MeasurementUnitType.DISTANCE,
          Number(transformedData['value']),
          1,
        );
      }
      if (this.counterType() === 'hours') {
        transformedData['value'] =
          Math.round(Number(transformedData['value']) * 10) / 10;
      }
    }

    // Emit the transformed values
    this.formValueChange.emit(transformedData);
  }
}
