import {
  Component,
  computed,
  effect,
  inject,
  OnInit,
  signal,
} from '@angular/core';
import { isDefined, isNullOrUndefined } from '../../../../../shared/utils';
import { CommonModule } from '@angular/common';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { Validators } from '@angular/forms';
import { ButtonModule } from 'primeng/button';
import {
  AccountsService,
  ClientResponse,
  CustomFieldDefinition,
  IdName,
  VendorResponse,
} from '../../../../../api';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import {
  createDropdownField,
  createTextField,
} from '../../../../../shared/models';
import { EntitySectionBaseComponent } from '../../base';
import { CustomFieldResponse } from '../../../models';
import { CustomFieldsDataAdapter } from '../../../services/adapters';
import { firstValueFrom, Observable } from 'rxjs';
import { DynamicDialogConfig } from 'primeng/dynamicdialog';

@Component({
  selector: 'app-custom-field-details-section',
  imports: [CommonModule, ButtonModule, GridComponent, DynamicFormComponent],
  templateUrl: './custom-field-details-section.component.html',
  styleUrl: './custom-field-details-section.component.scss',
})
export class CustomFieldDetailsSectionComponent
  extends EntitySectionBaseComponent<
    CustomFieldResponse | Record<string, CustomFieldDefinition[]>
  >
  implements OnInit
{
  private readonly dialogConfig = inject(DynamicDialogConfig, {
    optional: true,
  });
  private readonly accountsService = inject(AccountsService);
  private readonly customFieldsAdapter = inject(CustomFieldsDataAdapter);
  readonly customFieldDetails = computed(() => {
    const customFieldDetails: CustomFieldResponse =
      this.entity() as CustomFieldResponse;
    if (!isDefined(customFieldDetails)) return [];

    // Check if customFieldDetails is a CustomFieldResponse (has id property)
    if (!('id' in customFieldDetails)) return [];

    const [_ownerId, _entityTypeFromId, fieldId] =
      customFieldDetails.id.split('.');

    return [
      { key: 'Id', value: fieldId ?? 'None' },
      { key: 'Name', value: customFieldDetails.name ?? 'None' },
      {
        key: 'Applies To',
        value: customFieldDetails?._entityType?.name ?? 'None',
      },
      {
        key: 'Required',
        value: customFieldDetails.required === true ? 'Yes' : 'No',
      },
      {
        key: 'Type',
        value: customFieldDetails.type?.name ?? 'None',
      },
    ];
  });
  protected readonly selectOptionsLoaded = signal<boolean>(false);
  selectOptions: Record<string, { label: string; value: string | boolean }[]> =
    {};

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];

    effect(() => {
      const selectOptionsLoaded = this.selectOptionsLoaded();
      if (selectOptionsLoaded) {
        this.updateFormFields();
      }
    });
  }

  ngOnInit() {
    this.loadSelectOptions();
  }

  private loadSelectOptions(): void {
    const customField = this.entity() as CustomFieldResponse;
    let ownerId: string | undefined; // Explicitly string or undefined

    if (isDefined(this.dialogConfig?.data?.ownerId)) {
      ownerId = this.dialogConfig?.data?.ownerId;
    } else if (customField?.id && typeof customField.id === 'string') {
      const idParts = customField.id.split('.');
      if (idParts.length > 0) {
        ownerId = idParts[0];
      }
    }

    if (isNullOrUndefined(ownerId)) {
      this.selectOptions = {};
      this.selectOptionsLoaded.set(true);
      this.updateFormFields();
      return;
    }

    this.customFieldsAdapter.getCachedAssetTypes(ownerId).subscribe({
      next: (types) => {
        this.selectOptions = {
          assetTypes: types.items
            .map((item) => ({ label: item.name ?? '', value: item.id }))
            .sort((a, b) => a.label.localeCompare(b.label)),
          required: [
            { label: 'Yes', value: true },
            { label: 'No', value: false },
          ],
          types: [
            { label: 'Text', value: 'text' },
            { label: 'Memo', value: 'memo' },
            { label: 'Selection', value: 'combo' },
            { label: 'Yes/No', value: 'checkbox' },
            { label: 'Date', value: 'date' },
            { label: 'DateTime', value: 'datetime' },
            { label: 'URL', value: 'url' },
          ],
        };
        this.selectOptionsLoaded.set(true);
      },
      error: () => {
        this.selectOptionsLoaded.set(true);
      },
    });
  }

  protected override updateFormFields(): void {
    const customField = this.entity() as CustomFieldResponse;

    // Default values if customField is undefined
    let fieldId = '';
    let name = '';
    let entityTypeId = '';
    let required = false;
    let typeId = '';

    // Extract values from customField if it exists
    if (isDefined(customField) && isDefined(customField.id)) {
      const [_ownerId, _entityTypeFromId, extractedFieldId] =
        customField.id.split('.');
      fieldId = extractedFieldId || '';
      name = customField.name || '';
      entityTypeId = (customField._entityType as IdName)?.id || '';
      required = customField.required || false;
      typeId = (customField.type as IdName)?.id || '';
    }

    this.formFields = [
      createTextField('tag', 'Id', fieldId, {
        name: 'tag',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'Id is required',
          },
        ],
      }),
      createTextField('title', 'Name', name, {
        name: 'title',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'Name is required',
          },
        ],
      }),
      createDropdownField(
        'entityType',
        'Applies To',
        this.selectOptions['assetTypes'],
        entityTypeId,
        {
          name: 'entityType',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: 'Type is required',
            },
          ],
          disabled: !this.createMode(),
          props: {
            appendTo: 'body',
          },
        },
      ),
      createDropdownField(
        'required',
        'Required',
        this.selectOptions['required'],
        required,
        {
          name: 'required',
          validations: [
            {
              name: 'required',
              validator: Validators.required,
              message: 'Required is required',
            },
          ],
          props: {
            appendTo: 'body',
          },
        },
      ),
      createDropdownField('type', 'Type', this.selectOptions['types'], typeId, {
        name: 'type',
        validations: [
          {
            name: 'required',
            validator: Validators.required,
            message: 'Type is required',
          },
        ],
        props: {
          appendTo: 'body',
        },
      }),
    ];
  }

  protected override submitChanges(
    formData: Record<string, string | number | boolean | object>,
  ): void {
    const customField = this.entity();
    if (isNullOrUndefined(customField)) return;

    const customFieldData = Object.fromEntries(
      Object.entries({
        id: formData['tag'] as string,
        title: formData['title'] as string,
        type: formData['type'] as string,
        required: formData['required'] as boolean,
        values: formData['values'] as { key: string; value: string }[],
      }).filter(([_, value]) => isDefined(value)),
    );

    const [companyId, entityType, id] = (customField.id as string).split('.');
    firstValueFrom(this.accountsService.getCompany(companyId))
      .then((company) => {
        const customFields: Record<string, CustomFieldDefinition[]> =
          JSON.parse(JSON.stringify(company.customFields));
        const bucket = customFields[entityType] ?? [];
        const idx = bucket.findIndex((x) => x.id === id);
        if (idx > -1) {
          bucket[idx] = {
            ...bucket[idx],
            ...customFieldData,
          };
        }
        customFields[entityType] = bucket;

        let request$: Observable<ClientResponse | VendorResponse>;

        if (company.type === 'client') {
          request$ = this.accountsService.updateClientDetails(company.id, {
            customFields,
          });
        } else if (company.type === 'vendor') {
          request$ = this.accountsService.updateVendorDetails(company.id, {
            customFields,
          });
        } else {
          console.error(
            'Neither clientId nor vendorId found in route parameters',
          );
          return;
        }

        request$.pipe(takeUntilDestroyed(this.destroyRef)).subscribe({
          next: (response: ClientResponse | VendorResponse) => {
            this.isFormEditable.set(false);
            this.broadcastService.broadcast('entity-updated', {
              entityType: 'custom-field',
              operation: 'update',
              entityId: customField.id,
              data: response,
            });
          },
          error: (error) => {
            console.error('Failed to update custom field:', error);
            this.isFormEditable.set(true);
          },
        });
      })
      .catch(() => {});
  }

  protected override onFormValueChange(
    formData: Record<string, string | number | object>,
  ): void {
    const transformedData = { ...formData };

    // Transform entityType ID to IdName object
    if (
      isDefined(transformedData['entityType']) &&
      typeof transformedData['entityType'] === 'string'
    ) {
      const entityTypeOption = this.selectOptions?.['assetTypes']?.find(
        (option) => option.value === transformedData['entityType'],
      );

      if (entityTypeOption) {
        transformedData['entityType'] = {
          id: entityTypeOption.value,
          name: entityTypeOption.label,
        };
      }
    }

    this.formValueChange.emit(transformedData);
  }
}
