import { Injectable, inject } from '@angular/core';
import { Observable } from 'rxjs';

import { CompanyGroupResponse, AccountsService } from '../../../../api';
import { BaseTreeAdapter } from './base-tree.adapter.service';

@Injectable({
  providedIn: 'root',
})
export class CompanyGroupsDataAdapter extends BaseTreeAdapter<
  CompanyGroupResponse,
  { items: CompanyGroupResponse[]; count: number }
> {
  private readonly accountsService = inject(AccountsService);

  protected fetchEntities(
    owner: string,
    offset: number | undefined,
    limit: number | undefined,
    sortField: string | undefined,
    filters: string,
  ): Observable<{ items: CompanyGroupResponse[]; count: number }> {
    return this.accountsService.listCompanyGroups(
      owner,
      offset,
      limit,
      sortField,
      filters,
    );
  }

  getById(id: string): Observable<CompanyGroupResponse> {
    return this.accountsService.getCompanyGroup(id);
  }
}
