import { CommonModule } from '@angular/common';
import { Component, computed, inject, OnInit, signal } from '@angular/core';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { ReactiveFormsModule, Validators } from '@angular/forms';

import { ButtonModule } from 'primeng/button';
import { CardModule } from 'primeng/card';

import {
  AssetResponse,
  EntitiesService,
  IoTypeListItem,
  AssetAnalogParameter,
  AssetTemperatureParameter,
  AssetCurfewParameter,
} from '../../../../../api';
import { AppListsTranslations } from '../../../../../core/models';
import { UtilityService } from '../../../../../core/services/utility.service';
import { GridComponent } from '../../../../../shared/components/grid/grid.component';
import {
  createDropdownField,
  createNumberField,
  MeasurementUnitType,
  createModalListField,
  FormFieldConfig,
  ListFieldModalConfig,
  createDateField,
  createListboxField,
} from '../../../../../shared/models';
import { MeasurementUnitsService } from '../../../../../shared/services/measurement-units/measurement-units.service';
import { isNullOrUndefined } from '../../../../../shared/utils';
import { WEEKDAY_OPTIONS } from '../../../models';
import { EntitySectionBaseComponent } from '../../base';
import { DynamicFormComponent } from '../../../../../shared/components/forms/dynamic-form/dynamic-form.component';
import { ModalListFormComponent } from '../../../../../shared/components/forms/modal-list-form/modal-list-form.component';
import { HttpClient } from '@angular/common/http';

@Component({
  selector: 'app-asset-curfew-events-section',
  imports: [
    CommonModule,
    ReactiveFormsModule,
    ButtonModule,
    GridComponent,
    DynamicFormComponent,
    CardModule,
  ],
  templateUrl: './asset-curfew-events-section.component.html',
  styleUrl: './asset-curfew-events-section.component.scss',
})
export class AssetCurfewEventsSectionComponent
  extends EntitySectionBaseComponent<AssetResponse>
  implements OnInit
{
  private readonly http = inject(HttpClient);
  private readonly entitiesService = inject(EntitiesService);
  private readonly measurementUnitsService = inject(MeasurementUnitsService);
  private readonly utilityService = inject(UtilityService);

  timezones: { label: string; value: string }[] = [];

  protected readonly selectOptionsLoaded = signal<boolean>(false);
  selectOptions: Record<
    string,
    { label: string; value: string; type: string }[]
  > = {};

  readonly assetCurfewEvents = computed(() => {
    const asset = this.entity();
    const assetCurfewEvents = asset?.parameters?.curfews;
    if (isNullOrUndefined(assetCurfewEvents)) return [];

    return [
      {
        key: 'Working Hours',
        value: assetCurfewEvents
          .map((event) => `${event.from} - ${event.to}`)
          .join(', '),
      },
    ];
  });

  showModal = false;
  ioTypes: IoTypeListItem[] = [];
  modalTitle = '';

  constructor() {
    super();

    // Setup initial columns
    this.columns = [
      { field: 'key', header: '', transform: 'uppercase' },
      { field: 'value', header: '' },
    ];
  }

  ngOnInit(): void {
    this.loadTimezones();
  }

  private generateDescription(
    data: AssetAnalogParameter | AssetTemperatureParameter,
  ): string {
    return `Range of ${data.minRange} to ${data.maxRange} with a debounce of ${data.rangeDebounce} positions`;
  }

  private loadTimezones(): void {
    this.http
      .get<{ id: string; name: string }[]>('/assets/docs/timezones.json')
      .subscribe((data) => {
        this.timezones = data
          .map((tz) => ({ label: tz.id, value: tz.id }))
          .sort((a, b) => a.label.localeCompare(b.label));
        this.updateFormFields();
      });
  }

  protected override updateFormFields(): void {
    const assetCurfewModalConfig: ListFieldModalConfig<AssetCurfewParameter> = {
      modalComponent: ModalListFormComponent,
      modalTitle: 'External Tab',
      defaultItemProvider: () => ({
        from: '',
        to: '',
        timeZoneId: '',
        days: [],
      }),
      listItemFormatter: (item) => {
        const tabItem = item;
        return {
          id: tabItem.id,
          title: `${tabItem.from} - ${tabItem.to}`,
          display: `Between ${tabItem.from} and ${tabItem.to} on ${this.utilityService.getWeekdaysString(tabItem.days)}`,
          icon: 'clock',
        };
      },

      modalFields: (_item): FormFieldConfig[] => {
        return [
          createDateField('from', 'From', '', {
            name: 'from',
            placeholder: 'Select time',
            props: {
              timeOnly: true,
              showSeconds: true,
            },
            style: { width: '100%' },
          }),
          createDateField('to', 'To', '', {
            name: 'to',
            placeholder: 'Select time',
            props: {
              timeOnly: true,
              showSeconds: true,
            },
            style: { width: '100%' },
          }),
          createDropdownField('timeZoneId', 'Time Zone', this.timezones, '', {
            layout: 'horizontal',
            labelWidth: '1/3',
            placeholder: 'Select timezone',
            name: 'timeZone',
            props: {
              appendTo: 'body',
            },
          }),
          createListboxField('days', 'Weekdays', [], WEEKDAY_OPTIONS, {
            name: 'days',
            validations: [
              {
                name: 'required',
                validator: Validators.required,
                message: 'Days is required',
              },
            ],
            props: {
              checkmark: true,
              multiple: true,
            },
          }),
        ];
      },
      subHeader: AppListsTranslations['MODALS']['EXTERNAL-TABS']['DESC'],
    };

    this.formFields = [
      createModalListField(
        'assetCurfew',
        'Working Hours',
        this.entity()?.parameters?.curfews ?? [],
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'assetCurfew',
          props: {
            modalConfig:
              assetCurfewModalConfig as unknown as ListFieldModalConfig<unknown>,
          },
        },
      ),
    ];
  }

  protected override submitChanges(): void {
    const asset = this.entity();
    if (isNullOrUndefined(asset)) return;

    // Use the prepared data for the API update
    this.handleEntityUpdate(
      this.entitiesService
        .updateAsset(asset.id, {
          parameters: {
            //curfews: this.curfewEvents(),
          },
        })
        .pipe(takeUntilDestroyed(this.destroyRef)),
      'Working Hours updated successfully',
    );
  }

  updateAnalogFormFields(): void {
    this.formFields = [
      createDropdownField(
        'id',
        'Analog Input',
        this.selectOptions?.['analogInputTypes'] ?? [],
        '',
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'id',
          props: {
            appendTo: 'body',
          },
        },
      ),
      createNumberField('minRange', 'Min Range', 0, {
        layout: 'horizontal',
        labelWidth: '1/3',
        name: 'minRange',
      }),
      createNumberField('maxRange', 'Max Range', 100, {
        layout: 'horizontal',
        labelWidth: '1/3',
        name: 'maxRange',
      }),
      createNumberField('rangeDebounce', 'Range Debounce', 0, {
        layout: 'horizontal',
        labelWidth: '1/3',
        name: 'rangeDebounce',
      }),
      createNumberField('decValue', 'Drop Amount', 0, {
        layout: 'horizontal',
        labelWidth: '1/3',
        name: 'decValue',
      }),
      createNumberField('incValue', 'Increase Amount', 0, {
        layout: 'horizontal',
        labelWidth: '1/3',
        name: 'incValue',
      }),
    ];
  }

  updateTemperatureFormFields(): void {
    this.formFields = [
      createDropdownField(
        'id',
        'Temperature Input',
        this.selectOptions?.['temperatureInputTypes'] ?? [],
        '',
        {
          layout: 'horizontal',
          labelWidth: '1/3',
          name: 'id',
          props: {
            appendTo: 'body',
          },
        },
      ),
      createNumberField('minRange', 'Min Range', 0, {
        layout: 'horizontal',
        labelWidth: '1/3',
        name: 'minRange',
        props: {
          suffix: this.measurementUnitsService.unitSymbol(
            MeasurementUnitType.TEMPERATURE,
          ),
        },
      }),
      createNumberField('maxRange', 'Max Range', 100, {
        layout: 'horizontal',
        labelWidth: '1/3',
        name: 'maxRange',
        props: {
          suffix: this.measurementUnitsService.unitSymbol(
            MeasurementUnitType.TEMPERATURE,
          ),
        },
      }),
      createNumberField('rangeDebounce', 'Range Debounce', 0, {
        layout: 'horizontal',
        labelWidth: '1/3',
        name: 'rangeDebounce',
      }),
    ];
  }

  onClose() {
    this.showModal = false;
  }

  getDescription(
    analog: AssetAnalogParameter | AssetTemperatureParameter,
  ): string {
    return `Range of ${analog.minRange} to ${analog.maxRange} with a debounce of ${analog.rangeDebounce} positions`;
  }
}
