import { Injectable, inject } from '@angular/core';
import { Observable } from 'rxjs';

import { EntitiesService, CostCentreResponse } from '../../../../api';
import { BaseTreeAdapter } from './base-tree.adapter.service';

@Injectable({
  providedIn: 'root',
})
export class CostCentresDataAdapter extends BaseTreeAdapter<
  CostCentreResponse,
  { items: CostCentreResponse[]; count: number }
> {
  private readonly entitiesService = inject(EntitiesService);

  protected fetchEntities(
    owner: string,
    offset: number | undefined,
    limit: number | undefined,
    sortField: string | undefined,
    filters: string,
  ): Observable<{ items: CostCentreResponse[]; count: number }> {
    return this.entitiesService.listCostCentres(
      owner,
      offset,
      limit,
      sortField,
      filters,
    );
  }

  getById(id: string): Observable<CostCentreResponse> {
    return this.entitiesService.getCostCentre(id);
  }
}
