import { Injectable, inject, signal } from '@angular/core';
import { combineLatest, EMPTY, map, Observable, of } from 'rxjs';

import { isDefined, isNullOrUndefined } from '../../../../shared/utils';
import {
  EntitiesService,
  AccountsService,
  IdName,
  CustomFieldDefinition,
} from '../../../../api';
import { DataGridParams, EntityDataAdapter } from '../../../../shared/models';
import { RequestCacheService } from '../../../../shared/services/request-cache.service';
import { UtilityService } from '../../../../core/services/utility.service';
import {
  CustomFieldResponse,
  CUSTOM_FIELD_TYPES,
  CUSTOM_FIELD_TYPES_MAP,
  CustomFieldResponseList,
} from '../../models';

@Injectable({
  providedIn: 'root',
})
export class CustomFieldsDataAdapter
  implements EntityDataAdapter<CustomFieldResponse, CustomFieldResponse>
{
  private readonly entitiesService = inject(EntitiesService);
  private readonly accountsService = inject(AccountsService);
  private readonly cacheService = inject(RequestCacheService);
  private readonly utilityService = inject(UtilityService);
  assetTypes = signal<IdName[]>([]);
  types = signal<IdName[]>([]);

  getList(params: DataGridParams): Observable<CustomFieldResponseList> {
    const { owner, limit, offset, filters } = params;

    if (isNullOrUndefined(owner)) {
      return of({ items: [], count: 0, title: '', type: '', limit, offset });
    }

    return combineLatest([
      this.accountsService.getCompany(owner),
      this.getCachedAssetTypes(owner),
      this.getTypes(),
    ]).pipe(
      map(([company, assetTypes, types]) => {
        const items: CustomFieldResponse[] = [];
        Object.keys(company.customFields || {}).forEach((fieldType) => {
          (company.customFields?.[fieldType] || [])
            .filter((x) => x['owner'] === company.type)
            .forEach((field) => {
              items.push(
                this.customFieldDefinitionToCustomFieldResponse(
                  assetTypes.items,
                  types,
                  owner,
                  fieldType,
                  field,
                ),
              );
            });
        });
        this.assetTypes.set(assetTypes.items);
        this.types.set(types);

        return {
          title: 'Custom Fields',
          type: 'custom-field',
          count: items.length,
          limit: limit,
          offset: offset,
          items: this.filter(filters ?? '', items),
        };
      }),
    );
  }

  getById(_id: string) {
    const [ownerId] = _id.split('.');
    if (!ownerId) {
      return EMPTY;
    }

    const params: DataGridParams = {
      owner: ownerId,
      limit: 0, // We don't need pagination here
      offset: 0,
    };

    return this.getList(params).pipe(
      map((responseList) => {
        return responseList.items.find((item) => item.id === _id);
      }),
      map((item) => {
        if (!item) {
          return {} as CustomFieldResponse;
        }
        return item;
      }),
    );
  }

  customFieldDefinitionToCustomFieldResponse(
    entityTypes: IdName[],
    types: IdName[],
    ownerId: string,
    entityType: string,
    field: CustomFieldDefinition,
  ): CustomFieldResponse {
    return {
      id: `${ownerId}.${entityType}.${field.id}`,
      tag: field.id,
      name: field.title,
      required: field.required,
      _entityType: entityTypes.find((x) => x.id === entityType),
      type: types.find((x) => x.id === field.type),
      values: (field.values ?? []).map((x) => x.key).join('\n'),
    };
  }

  getTypes(): Observable<IdName[]> {
    return of(
      CUSTOM_FIELD_TYPES.map((type) => ({
        id: type,
        name: CUSTOM_FIELD_TYPES_MAP[type],
      })),
    );
  }

  getCachedAssetTypes(ownerId: string): Observable<{ items: IdName[] }> {
    const cacheKey = `assetTypes-${ownerId}`;
    return this.cacheService.getOrFetch(cacheKey, () =>
      this.entitiesService.listAssetTypes(ownerId),
    );
  }

  filter(filter: string, items: CustomFieldResponse[]): CustomFieldResponse[] {
    const matches = (f: string, item: CustomFieldResponse): boolean => {
      const [field, match] = f.split('=');
      if (!match) {
        return true;
      }
      const value = this.getNestedValue(item, field) ?? '';
      if (match.includes('*')) {
        // User specified text search, be generous in matching.
        return this.utilityService
          .escapeRqlValue(value)
          .toLowerCase()
          .includes(match.replace(/\*/g, '').toLowerCase());
      }
      // Chosen from predefined list, match exactly.
      return value.toLowerCase() === match.toLowerCase();
    };

    // The filter string could look like this, we need to support logical OR filters
    //  (entityType.id=simcard|entityType.id=asset),type.id=blah

    const filters = (filter || '')
      .split(',')
      .filter((term) => term)
      .map((term) => {
        if (term.includes('|')) {
          return term.slice(1, term.length - 1).split('|');
        }
        return [term];
      });

    return filters
      .reduce(
        (result, column) =>
          result.filter((item) => column.some((term) => matches(term, item))),
        items,
      )
      .sort((a, b) => {
        const aName = a.name.toLowerCase();
        const bName = b.name.toLowerCase();
        if (aName < bName) {
          return -1;
        }
        if (aName > bName) {
          return 1;
        }
        return 0;
      });
  }

  getCustomFieldResponseFromCompany(
    company: CustomFieldResponseList,
    id: string,
  ): CustomFieldResponse | undefined {
    const customField = company.items.find((x) => x.id === id);
    if (customField) {
      return customField;
    }
    return undefined;
  }

  private getNestedValue<T>(obj: T, path: string): string | undefined {
    return path.split('.').reduce((acc, key) => {
      if (
        isDefined(acc) &&
        acc !== null &&
        typeof acc === 'object' &&
        key in acc
      ) {
        return (acc as Record<string, unknown>)[key];
      }
      return undefined;
    }, obj as unknown) as string | undefined;
  }
}
