import { Injectable, inject } from '@angular/core';
import { Observable, of } from 'rxjs';

import { isNullOrUndefined } from '../../../../shared/utils';
import {
  SmsGatewayProviderListItem,
  EntitiesService,
  SmsGatewayProviderResponse,
} from '../../../../api';
import {
  DataGridParams,
  GridDataService,
  GridResponse,
} from '../../../../shared/models';

@Injectable({
  providedIn: 'root',
})
export class SmsGatewayProvidersDataAdapter
  implements GridDataService<SmsGatewayProviderListItem>
{
  private readonly entitiesService = inject(EntitiesService);

  getList(
    params: DataGridParams,
  ): Observable<GridResponse<SmsGatewayProviderListItem>> {
    const { owner, limit, offset, sortField, filters } = params;

    if (isNullOrUndefined(owner)) {
      return of({ items: [], count: 0 });
    }

    return this.entitiesService.listSmsGatewayProviders(
      owner,
      offset,
      limit,
      sortField as string,
      filters,
    );
  }

  getById(id: string): Observable<SmsGatewayProviderResponse> {
    return this.entitiesService.getSmsGatewayProvider(id);
  }
}
